import { CircuitMaster } from './CircuitMaster';
export class ErrorInterceptor {
    private static isInternal = false;
    static runInternal<T>(fn: () => T): T {
        this.isInternal = true;
        try { return fn(); } finally { this.isInternal = false; }
    }
    static boot() {
        const origErr = console.error;
        console.error = (...args) => {
            origErr(...args);
            if (this.isInternal) return;
            // Send to SAEREWorkerProxy
        };
        window.addEventListener('error', e => { if (!this.isInternal) { /* send */ } });
        window.addEventListener('unhandledrejection', e => { if (!this.isInternal) { /* send */ } });

        // HMR Death Loop Protection
        if (import.meta.hot) {
            import.meta.hot.on('vite:beforeUpdate', () => {
                if (CircuitMaster.isShadowTesting()) {
                    console.warn('[SAERE] Pausing HMR during Shadow Test');
                    import.meta.hot?.decline();
                }
            });
        }
    }
}`,
