export class OracleEye {
    static needsCapture = false;
    private static lastState: string | null = null;
    static boot() {
        const origRAF = window.requestAnimationFrame;
        window.requestAnimationFrame = (cb) => {
            if (this.needsCapture) this.capture(document.querySelectorAll('canvas'));
            return origRAF(cb);
        };
    }
    static capture(canvases: NodeListOf<HTMLCanvasElement>) {
        if (!canvases.length) return;
        try { 
            this.lastState = canvases[0].toDataURL('image/webp', 0.5); 
            this.needsCapture = false; 
        } catch (e) {
            console.warn('[OracleEye] Tainted canvas detected.');
        }
    }
}`,
  'src/HAS/workers/has.worker.ts': `
import { OmniPromptEngine } from '../OmniPromptEngine';
import { MicroHeuristicEngine } from '../MicroHeuristicEngine';
import { CircuitMaster } from '../CircuitMaster';
import { ConstitutionalCore } from '../ConstitutionalCore';
import { RealJudge } from '../RealJudge';

let isProcessing = false;
const queue: string[] = [];

self.onmessage = async (e) => {
    if (e.data.type === 'NEW_ERROR') { queue.push(e.data.payload); processQueue(); }
};

async function processQueue() {
    if (isProcessing || !queue.length) return;
    isProcessing = true;
    const err = queue.shift()!;
    try {
        const sig = err.substring(0, 100);
        if (CircuitMaster.isOpen(sig)) return;

        const offlineFix = MicroHeuristicEngine.analyze(err);
        if (offlineFix) return;

        const omni = await OmniPromptEngine.analyzeAndFix(err, '');
        const val = ConstitutionalCore.validate({ type: 'EDIT_FILE', content: omni.proposedFix, confidence: omni.confidence });
        if (!val.allowed) return;

        const judge = await RealJudge.verify(omni.proposedFix);
        if (!judge.passed) CircuitMaster.recordFailure(sig);
    } finally {
        isProcessing = false;
        if (queue.length) setTimeout(processQueue, 100);
    }
}`,
