export class RealJudge {
    static async verify(code: string) {
        const failed: string[] = [];
        if (/while\\s*\\(\\s*true\\s*\\)/.test(code) && !/break/.test(code)) failed.push('Infinite loop');
        if (/eval\\s*\\(/.test(code)) failed.push('eval() usage');
        return { passed: failed.length === 0, failedChecks: failed };
    }
}`,

