export class DependencyOracle {
    private static map = new Map<string, string[]>();
    static buildGraph(files: {path: string, content: string}[]) {
        this.map.clear();
        const re = /import\\s+.*?\\s+from\\s+['"]([^'"]+)['"]/g;
        for (const f of files) {
            let m; while ((m = re.exec(f.content)) !== null) {
                if (!this.map.has(m[1])) this.map.set(m[1], []);
                this.map.get(m[1])!.push(f.path);
            }
        }
    }
    static getImpacted(p: string) { return this.map.get(p) || []; }
}`,

