export class CircuitMaster {
    private static circuits = new Map<string, number>();
    private static shadowTesting = false;

    static isShadowTesting() { return this.shadowTesting; }
    static setShadowTesting(val: boolean) { this.shadowTesting = val; }

    static isOpen(sig: string) { return (this.circuits.get(sig) || 0) >= 3; }
    static recordFailure(sig: string) {
        this.circuits.set(sig, (this.circuits.get(sig) || 0) + 1);
