export class WorldSimulator {
    private static buffers = new Map<string, { data: Float32Array, head: number }>();
    static observe(ep: string, ms: number) {
        if (!this.buffers.has(ep)) this.buffers.set(ep, { data: new Float32Array(1024), head: 0 });
        const b = this.buffers.get(ep)!;
        b.data[b.head] = ms;
        b.head = (b.head + 1) % 1024;
    }
}`,
