  private static readonly PUBLIC_URL = 'https://ais-dev-5xogkxtdovdaqskfdjmhqf-41062462252.asia-east1.run.app';
  private static auditQueue: string[] = [];

  private static async autoPush() {
    console.log('[Ouroboros Daemon] Initiating Scheduled Auto-Push to GitHub...');
    try {
      const { execSync } = await import('child_process');
      // We retrieve the token from the persisted file to ensure portability across remixed accounts
