  // Recursively find all TS/TSX files
  private static async populateAuditQueue(dir: string) {
    try {
      const files = await fs.promises.readdir(dir, { withFileTypes: true });
      // Sort files alphabetically to ensure consistent sequential order
      files.sort((a, b) => a.name.localeCompare(b.name));

      for (const file of files) {
        const res = path.resolve(dir, file.name);
        if (file.isDirectory() && !res.includes('node_modules') && !res.includes('dist') && !file.name.startsWith('.')) {
          await this.populateAuditQueue(res);
        } else if (file.isFile() && (res.endsWith('.ts') || res.endsWith('.tsx')) && !res.endsWith('.d.ts')) {
          this.auditQueue.push(res);
        }
      }
    } catch (e) {
      console.error('[Ouroboros Daemon] Failed to populate audit queue:', e);
    }
  }

  private static readonly MAX_RAM_MB = 250; // Adaptive RAM Limiter threshold

  static start() {
    if (this.isActive) return;
    this.isActive = true;
    console.log('[Ouroboros Protocol] Immortal Daemon Engaged. 24/7 Autonomy Active with Adaptive RAM Limiter.');

    this.interval = setInterval(async () => {
      try {
        // [ARCHITECT OVERRIDE] Pause daemon if Architect is running manual tasks
        const architectFlagPath = path.join(process.cwd(), '.architect_active');
        if (fs.existsSync(architectFlagPath)) {
          return;
        }

        const now = Date.now();
        const uptime = process.uptime();
        const currentRamMB = Math.round(process.memoryUsage().rss / 1024 / 1024);

        // 1. Health Check & Telemetry
        if (Math.floor(uptime) % 300 === 0) { // Every ~5 mins
          console.log(`[Ouroboros Daemon] Heartbeat. Uptime: ${Math.floor(uptime)}s, Memory: ${currentRamMB}MB`);
        }

        // [ADAPTIVE RAM LIMITER] Check memory before executing heavy tasks
        if (currentRamMB > this.MAX_RAM_MB) {
          console.warn(`[Ouroboros Daemon] RAM usage high (${currentRamMB}MB > ${this.MAX_RAM_MB}MB). Throttling background tasks to prevent VFS Deadlock.`);
          // Try to force GC if exposed (requires node --expose-gc, but we can't guarantee it here, so we just throttle)
          if (global.gc) {
            try { global.gc(); } catch (e) {}
          }
          return; // Skip this tick's heavy tasks
        }

        // 2. Internal Defibrillator (Self-Ping)
        try {
          fetch(`${this.PUBLIC_URL}/api/system/heartbeat`).catch(() => {});
        } catch (e) {}

        // 3. Scheduled Auto-Push (Every 1 hour)
        if (now - this.lastPushTime > this.PUSH_THRESHOLD) {
          this.lastPushTime = now;
          await this.autoPush();
        }

        // 4. Deep Component Audit (Sequential Micro-Auditing)
        // Runs every 10 minutes to deeply analyze one component at a time in sequence
        if (now - this.lastAuditTime > this.AUDIT_THRESHOLD) {
          this.lastAuditTime = now;

          if (this.auditQueue.length === 0) {
            console.log('[Ouroboros Daemon] Audit Queue empty. Repopulating from /src sequentially...');
            await this.populateAuditQueue(path.join(process.cwd(), 'src'));
          }

          // Use shift() for FIFO (First-In-First-Out) to maintain sequence
          const targetFile = this.auditQueue.shift();
          if (targetFile) {
            console.log(`[Ouroboros Daemon] Initiating Sequential Deep Audit on: ${targetFile}`);
            try {
              const { OmniPromptEngine } = await import('./src/HAS/OmniPromptEngine');
              const { OmniGraph } = await import('./src/services/supremeTools/ASTEngine');

              // [SUPREME PROTOCOL] Use OmniGraph to extract semantic context before audit
              const graph = new OmniGraph();
              const semanticContext = graph.extractSemanticContext(targetFile) || 'No semantic context available';
              const dependencies = graph.traceDependencies(targetFile) || [];

              OmniPromptEngine.analyzeAndFix(
                "Deep Component Audit", 
                `Perform a rigorous Deep Component Audit on the file: ${targetFile}. 
                1. Check for stability, efficiency, and maximum functionality.
                2. Look for logical flaws, edge cases, memory leaks, and performance bottlenecks (O(n) issues).
                3. Ensure it follows the highest Tier-God Architect standards.
                4. If flawed, fix it immediately. If perfect, report 'PERFECT'.
                Do not just look for syntax errors; analyze the deep logic.

                [SUPREME CONTEXT INJECTED]
                Dependencies: ${JSON.stringify(dependencies)}
                Semantic Structure: ${JSON.stringify(semanticContext)}`
              ).then(result => {
                console.log(`[Ouroboros Daemon] Audit Completed for ${path.basename(targetFile)}:`, result);
              }).catch(err => {
                console.error(`[Ouroboros Daemon] Audit Failed for ${path.basename(targetFile)}:`, err.message);
              });
            } catch (importErr) {
              console.error('[Ouroboros Daemon] Failed to load OmniPromptEngine for audit:', importErr);
            }
          }
        }

        // 5. Autonomous Self-Prompting (Routine Maintenance)
        if (now - this.lastTaskTime > this.IDLE_THRESHOLD) {
          console.log('[Ouroboros Daemon] System Idle. Initiating Routine Maintenance...');
          this.lastTaskTime = now; 

          try {
            const { OmniPromptEngine } = await import('./src/HAS/OmniPromptEngine');
            OmniPromptEngine.analyzeAndFix(
              "Routine Maintenance", 
              "System is idle. Review recent logs, clear temporary caches, and ensure system stability."
            ).then(result => {
              console.log('[Ouroboros Daemon] Maintenance Task Completed:', result);
            }).catch(err => {
              console.error('[Ouroboros Daemon] Maintenance Task Failed:', err.message);
            });
          } catch (importErr) {
            console.error('[Ouroboros Daemon] Failed to load OmniPromptEngine:', importErr);
          }
        }

      } catch (e) {
        console.error('[Ouroboros Daemon] Loop Error:', e);
      }
    }, this.TICK_RATE);
  }

  static stop() {
    this.isActive = false;
    if (this.interval) clearInterval(this.interval);
    console.log('[Ouroboros Protocol] Immortal Daemon Halted.');
  }

  static registerActivity() {
    this.lastTaskTime = Date.now();
  }
}

async function startServer() {
  const app = express();
  const server = http.createServer();
  const PORT = 3000;

  // Setup Socket.IO for Terminal FIRST
  const io = new SocketIOServer(server, {
    path: '/terminal-socket/',
    destroyUpgrade: false,
    cors: {
      origin: '*',
      methods: ['GET', 'POST']
    }
  });
  setupTerminalSocket(io);

  // Setup WebSocket (Yjs) FIRST
  await setupWebSocket(server);

  // THEN attach Express
  server.on('request', app);
  app.set('server', server);

  app.set('trust proxy', 1); // Trust first proxy for rate limiting

  app.use(express.json({ limit: '50mb' }));
  app.use(express.urlencoded({ extended: true, limit: '50mb' }));
  app.use(express.raw({ type: '*/*', limit: '50mb' }));

  // WebContainer Headers - Required for SharedArrayBuffer
  app.use((req, res, next) => {
    if (res.headersSent) return next();
    res.setHeader('Cross-Origin-Opener-Policy', 'same-origin');
    res.setHeader('Cross-Origin-Embedder-Policy', 'require-corp');
    res.setHeader('Cross-Origin-Resource-Policy', 'cross-origin');
    next();
  });

  // Ensure static files are served with correct headers and NO redirects
  app.use((req, res, next) => {
    if (res.headersSent) return next();

    if (req.path.endsWith('.wasm')) {
      res.setHeader('Content-Type', 'application/wasm');
      res.setHeader('Cross-Origin-Opener-Policy', 'same-origin');
      res.setHeader('Cross-Origin-Embedder-Policy', 'require-corp');

      // Try to serve from node_modules if it's a known wasm file
      const filename = path.basename(req.path);
      let wasmPath = '';

      if (filename === 'sql-wasm.wasm') {
        wasmPath = path.join(process.cwd(), 'node_modules', 'sql.js', 'dist', 'sql-wasm.wasm');
      } else if (filename === 'sqlite3.wasm') {
        wasmPath = path.join(process.cwd(), 'node_modules', '@sqlite.org', 'sqlite-wasm', 'dist', 'sqlite3.wasm');
      } else if (filename === 'web-tree-sitter.wasm' || filename === 'tree-sitter.wasm') {
        wasmPath = path.join(process.cwd(), 'node_modules', 'web-tree-sitter', 'web-tree-sitter.wasm');
      } else if (filename.startsWith('tree-sitter-')) {
        wasmPath = path.join(process.cwd(), 'node_modules', 'tree-sitter-wasms', 'out', filename);
      }

      if (wasmPath && fs.existsSync(wasmPath)) {
        try {
          res.type('application/wasm');
          return res.sendFile(wasmPath, (err) => {
            if (err && !res.headersSent) {
              res.status(404).send('WASM file error');
            }
          });
        } catch (e) {
          if (!res.headersSent) {
            return res.status(500).send('Internal WASM Error');
          }
          return;
        }
      }

      // Check if it exists in public directory
      const publicPath = path.join(process.cwd(), 'public', req.path);
      if (fs.existsSync(publicPath)) {
        try {
          return res.sendFile(publicPath, (err) => {
            if (err && !res.headersSent) {
              res.status(404).send('WASM file error');
            }
          });
        } catch (e) {
          if (!res.headersSent) {
            return res.status(500).send('Internal WASM Error');
          }
          return;
        }
      }

      // If not found, return 404 to prevent SPA fallback from serving index.html
      return res.status(404).send('WASM file not found');
    }
    next();
  });

  app.use(express.static(path.join(process.cwd(), 'public'), {
    setHeaders: (res, path) => {
      res.setHeader('Cross-Origin-Opener-Policy', 'same-origin');
      res.setHeader('Cross-Origin-Embedder-Policy', 'require-corp');
      if (path.endsWith('sw.js')) {
        res.setHeader('Service-Worker-Allowed', '/');
      }
    }
  }));

  app.get('/sw.js', (req, res) => {
    res.setHeader('Content-Type', 'application/javascript');
    res.setHeader('Service-Worker-Allowed', '/');
    res.setHeader('Cross-Origin-Opener-Policy', 'same-origin');
    res.setHeader('Cross-Origin-Embedder-Policy', 'require-corp');
    res.sendFile(path.join(process.cwd(), 'public', 'sw.js'));
  });

  // console.log('JSON database initialized.');

  // Health Check Route (Required by AI Studio Platform)
  app.get('/api/health', (req, res) => {
    res.json({ status: 'ok' });
  });

  // The External Defibrillator (Ouroboros Protocol)
  // Ping this endpoint via cron-job.org every 5 mins to keep the container alive 24/7
  app.get('/api/system/heartbeat', (req, res) => {
    ShadowDaemon.registerActivity(); // Register ping as activity to delay self-prompting if desired, or keep separate.
    res.json({ status: 'alive', protocol: 'ouroboros', timestamp: Date.now() });
  });

  // Log Route for Debugging
  app.post('/api/log', (req, res) => {
    const logData = JSON.stringify(req.body);
    // console.log('[Frontend Log]', logData);
    fs.appendFileSync('frontend_error.log', logData + '\n');
    res.json({ success: true });
  });

  // Global Rewrite /ham-api to /api
  app.use((req, res, next) => {
    if (req.url.startsWith('/ham-api')) {
      req.url = req.url.replace('/ham-api', '/api');
    }
    next();
  });

  // Mount Routes (Cloud Fortress)
  const apiCors = cors({ 
    origin: '*', 
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization', 'x-private-source-auth', 'x-goog-api-key']
  });

  app.use('/api', apiCors);
  app.use('/api', geminiRouter);
  app.use('/api/private-source', privateSourceRouter);
  app.use('/api/tunnel', tunnelRouter);
  app.use('/api/shell', shellRouter);
  app.use('/api/fs', fsBridgeRouter);
  app.use('/api/supreme', supremeRouter);

  // The Great Proxy: Dynamic API Bridge & HTML Rewriter (The Singularity Engine v9 - The Singularity Window)
  setupProxyRoutes(app);

  // Special Routes
  // Removed legacy routes

  // Vite middleware for development
  if (process.env.NODE_ENV !== 'production') {
    const { createServer: createViteServer } = await import('vite');
    const vite = await createViteServer({
      server: { 
        middlewareMode: true,
        hmr: { server } // Pass our HTTP server to Vite for HMR WebSockets
      },
      appType: 'spa',
      root: process.cwd(), // Set root to the current working directory (project root)
    });
    app.use(vite.middlewares);
  } else {
    app.use(express.static('dist'));
    app.get('*', (req, res) => {
      const indexPath = path.resolve(process.cwd(), 'dist', 'index.html');
      if (fs.existsSync(indexPath)) {
        res.sendFile(indexPath);
      } else {
        res.status(404).send('Application not built. Run "npm run build" first.');
      }
    });
  }

  server.listen(PORT, '0.0.0.0', () => {
    console.log(`Server running on http://localhost:${PORT}`);
    console.log(`  ➜  Local:   http://localhost:${PORT}/`);

    // Start Shadow Daemon (Ouroboros Protocol)
    ShadowDaemon.start();
  });
}

startServer().catch(err => {
  console.error('CRITICAL: Failed to start server:', err);
  process.exit(1);
});

