          // PROTOKOL FIX: Service Worker Registration — PRODUCTION ONLY.
          // In development, main.tsx already unregisters stale SWs. If we register here
          // too (without a PROD guard), the 'updatefound' event fires on every Vite rebuild
          // because main.tsx just unregistered the SW, so this registration is a fresh install.
          // Fresh install → updatefound fires → removeItem('coiReloaded') → window.location.reload()
          // → main.tsx unregisters again → next boot re-registers → updatefound → infinite reload loop.
          if ('serviceWorker' in navigator && import.meta.env.PROD) {
            setLoadingStatus('Registering Service Worker...');
            try {
              const swUrl = `${window.location.origin}/sw.js`;
              const registration = await navigator.serviceWorker.register(swUrl, { 
