              });

              // Only reload for SW UPDATES (not fresh installs) to avoid reload loop.
              // A fresh install always fires updatefound; limit to cases where there's an
              // existing active controller being replaced.
              registration.addEventListener('updatefound', () => {
                if (navigator.serviceWorker.controller) {
                  // There was an existing active SW — this is a real update.
                  sessionStorage.removeItem('coiReloaded');
                  window.location.reload();
                }
              });

              if (registration.active && !navigator.serviceWorker.controller) {
                if (!sessionStorage.getItem('coiReloaded')) {
                  sessionStorage.setItem('coiReloaded', 'true');
                  window.location.reload();
                }
              }

              navigator.serviceWorker.addEventListener('controllerchange', () => {
                if (!sessionStorage.getItem('coiReloaded')) {
                  sessionStorage.setItem('coiReloaded', 'true');
                  window.location.reload();
                }
              });

              await Promise.race([
                navigator.serviceWorker.ready,
                new Promise(resolve => setTimeout(resolve, 3000))
              ]);
              setLoadingStatus('Service Worker: Ready');
            } catch (e) {
              console.warn('[App] Service Worker registration failed:', e);
