import { Opcode, OmniASTNode } from '../core/types';
import { TokenType } from './lexer';
import { ParserExpressions_Part1 } from './parser_expressions_Part1';

export class ParserExpressions_Part2 extends ParserExpressions_Part1 {
    protected unary(): OmniASTNode {
        const operators: Opcode[] = [];

        while (true) {
            if (this.match(TokenType.OPERATOR, Opcode.SUB)) {
                operators.push(Opcode.SUB);
            } else if (this.match(TokenType.OPERATOR, Opcode.ADD)) {
                operators.push(Opcode.ADD);
            } else if (this.match(TokenType.OPERATOR, Opcode.NOT)) {
                operators.push(Opcode.NOT);
            } else if (this.match(TokenType.KEYWORD, Opcode.TYPEOF) || this.match(TokenType.OPERATOR, Opcode.TYPEOF)) {
                operators.push(Opcode.TYPEOF);
            } else if (this.match(TokenType.OPERATOR, Opcode.INC)) {
                operators.push(Opcode.INC);
            } else if (this.match(TokenType.OPERATOR, Opcode.DEC)) {
                operators.push(Opcode.DEC);
            } else if (this.match(TokenType.OPERATOR, Opcode.SPREAD)) {
                operators.push(Opcode.SPREAD);
            } else if (this.match(TokenType.KEYWORD, Opcode.AWAIT)) {
                operators.push(Opcode.AWAIT);
            } else {
                break;
            }
        }

        let expr = this.call();

        for (let i = operators.length - 1; i >= 0; i--) {
            const op = operators[i];
            if (op === Opcode.SUB) expr = this.node(Opcode.SUB, [0, expr]);
            else if (op === Opcode.ADD) expr = this.node(Opcode.ADD, [0, expr]);
            else if (op === Opcode.NOT) expr = this.node(Opcode.NOT, [expr]);
            else if (op === Opcode.TYPEOF) expr = this.node(Opcode.TYPEOF, [expr]);
            else if (op === Opcode.INC) expr = this.node(Opcode.INC, [expr, true]);
            else if (op === Opcode.DEC) expr = this.node(Opcode.DEC, [expr, true]);
            else if (op === Opcode.SPREAD) expr = this.node(Opcode.SPREAD, [expr]);
            else if (op === Opcode.AWAIT) expr = this.node(Opcode.AWAIT, [expr]);
        }

        return expr;
    }

    protected call(): OmniASTNode {
        let expr = this.primary();

        while (true) {
            if (this.match(TokenType.PUNCTUATION, '(')) {
                expr = this.finishCall(expr);
            } else if (this.match(TokenType.PUNCTUATION, '.') || this.match(TokenType.OPERATOR, Opcode.OPTIONAL_CHAIN)) {
                const startToken = this.previous();
                const isOptional = startToken.value === Opcode.OPTIONAL_CHAIN;
                const name = this.consume(TokenType.IDENTIFIER, "Expect property name").value as string;
                if (typeof expr === 'string' && expr === 'OS') {
                    expr = this.node(Opcode.OS_CALL, [name], startToken);
                } else if (typeof expr === 'object' && expr !== null && (expr as any).type === Opcode.OS_CALL) {
                    expr = this.node(Opcode.OS_CALL, [`${(expr as any).args[0]}.${name}`], startToken);
                } else {
                    expr = this.node(isOptional ? Opcode.OPTIONAL_CHAIN : Opcode.GET, [expr, `"${name}"`], startToken);
                }
            } else if (this.match(TokenType.PUNCTUATION, '[')) {
                const startToken = this.previous();
                const index = this.expression();
                this.consume(TokenType.PUNCTUATION, "Expect ']' after index", ']');
                expr = this.node(Opcode.GET, [expr, index], startToken);
            } else {
                break;
            }
        }

        if (this.match(TokenType.OPERATOR, Opcode.INC)) {
            expr = this.node(Opcode.INC, [expr, false]); // false = postfix
        } else if (this.match(TokenType.OPERATOR, Opcode.DEC)) {
            expr = this.node(Opcode.DEC, [expr, false]); // false = postfix
        }

        return expr;
    }

    protected finishCall(callee: OmniASTNode): OmniASTNode {
        const startToken = this.previous();
        const args: OmniASTNode[] = [];
        if (!this.check(TokenType.PUNCTUATION, ')')) {
            do {
                if (args.length >= 255) {
                    throw new Error(`[Parser Error] Line ${this.peek().line}: Can't have more than 255 arguments.`);
                }
                args.push(this.expression());
            } while (this.match(TokenType.PUNCTUATION, ','));
        }
        this.consume(TokenType.PUNCTUATION, "Expect ')' after arguments", ')');

        if (typeof callee === 'object' && callee !== null && (callee as any).type === Opcode.OS_CALL) {
            return this.node(Opcode.OS_CALL, [(callee as any).args[0], ...args], startToken);
        }

        return this.node(Opcode.CALL, [callee, ...args], startToken);
    }

    protected primary(): OmniASTNode {
        if (this.match(TokenType.NUMBER)) return this.previous().value as number;

        if (this.match(TokenType.STRING)) {
            const token = this.previous();
            if (token.quoteType === '`') {
                return this.parseTemplateLiteral(token.value as string);
            }
            return `"${token.value}"`;
        }

        let isAsync = false;
        if (this.match(TokenType.KEYWORD, Opcode.ASYNC)) {
            if (this.match(TokenType.KEYWORD, Opcode.FUNC)) {
                return (this as any).funcDeclaration(false, true, true);
            }
            isAsync = true;
        }

        if (this.match(TokenType.IDENTIFIER)) {
            const val = this.previous().value as string;

            // Arrow function: x => {}
            if (this.match(TokenType.OPERATOR, Opcode.ARROW)) {
                const startToken = this.previous();
                const body = this.match(TokenType.PUNCTUATION, '{') ? (this as any).block() : [this.node(Opcode.RETURN, [this.expression()], startToken)];
                return this.node(Opcode.FUNC, ["", [val], body, isAsync], startToken);
            }

            if (isAsync) {
                this.current -= 2;
                this.advance(); // re-consume IDENTIFIER
            }

            return val;
        }

        if (this.match(TokenType.KEYWORD, Opcode.TRUE)) return true;
        if (this.match(TokenType.KEYWORD, Opcode.FALSE)) return false;
        if (this.match(TokenType.KEYWORD, Opcode.NULL)) return null;

        if (this.match(TokenType.KEYWORD, Opcode.THIS)) return this.node(Opcode.THIS);
        if (this.match(TokenType.KEYWORD, Opcode.SUPER)) return this.node(Opcode.SUPER);
        if (this.match(TokenType.KEYWORD, Opcode.OS_CALL)) return "OS";
        if (this.match(TokenType.KEYWORD, Opcode.NEW)) {
            const startToken = this.previous();
            const expr = this.call();
            if (typeof expr === 'object' && expr !== null && (expr as any).type === Opcode.CALL) {
                return this.node(Opcode.NEW, (expr as any).args, startToken);
            }
            return this.node(Opcode.NEW, [expr], startToken);
        }

        if (this.match(TokenType.KEYWORD, Opcode.FUNC)) {
            return (this as any).funcDeclaration(false, true, isAsync); // true = isAnonymous
        }

        if (this.match(TokenType.KEYWORD, Opcode.IMPORT)) {
            const startToken = this.previous();
            const path = this.expression();
            return this.node(Opcode.IMPORT, [path], startToken);
        }

        if (this.match(TokenType.PUNCTUATION, '(')) {
            const startToken = this.previous();
            const startPos = this.current;
            let isArrow = false;
            let params = [];
            if (!this.check(TokenType.PUNCTUATION, ')')) {
                do {
                    if (this.check(TokenType.IDENTIFIER)) {
                        params.push(this.peek().value);
                        this.advance();
                    } else {
                        break;
                    }
                } while (this.match(TokenType.PUNCTUATION, ','));
            }
            if (this.match(TokenType.PUNCTUATION, ')') && this.match(TokenType.OPERATOR, Opcode.ARROW)) {
                isArrow = true;
            }

            if (isArrow) {
                const arrowToken = this.previous();
                const body = this.match(TokenType.PUNCTUATION, '{') ? (this as any).block() : [this.node(Opcode.RETURN, [this.expression()], arrowToken)];
                return this.node(Opcode.FUNC, ["", params, body, isAsync], startToken);
            } else {
                this.current = startPos;
                const expr = this.expression();
                this.consume(TokenType.PUNCTUATION, "Expect ')' after expression", ')');
                if (isAsync) {
                    throw new Error(`[Parser Error] Line ${this.peek().line}: Invalid async expression.`);
                }
                return expr;
            }
        }

        if (isAsync) {
            throw new Error(`[Parser Error] Line ${this.peek().line}: Invalid async expression.`);
        }

        if (this.match(TokenType.PUNCTUATION, '[')) {
            const startToken = this.previous();
            const elements: OmniASTNode[] = [];
            if (!this.check(TokenType.PUNCTUATION, ']')) {
                do {
                    elements.push(this.expression());
                } while (this.match(TokenType.PUNCTUATION, ','));
            }
            this.consume(TokenType.PUNCTUATION, "Expect ']' after array elements", ']');
            return this.node(Opcode.ARRAY, elements, startToken);
        }

        if (this.match(TokenType.PUNCTUATION, '{')) {
            const startToken = this.previous();
            const properties: OmniASTNode[] = [];
            if (!this.check(TokenType.PUNCTUATION, '}')) {
                do {
                    if (this.match(TokenType.OPERATOR, Opcode.SPREAD)) {
                        const spreadToken = this.previous();
                        const expr = this.expression();
                        properties.push(this.node(Opcode.SPREAD, [expr], spreadToken), null as any);
                    } else {
                        let key: string;
                        if (this.match(TokenType.IDENTIFIER) || this.match(TokenType.STRING)) {
                            key = this.previous().value as string;
                        } else {
                            throw new Error(`[Parser Error] Line ${this.peek().line}: Expect property name`);
                        }

                        let value: OmniASTNode;
                        if (this.match(TokenType.PUNCTUATION, ':')) {
                            value = this.expression();
                        } else {
                            if (this.previous().type === TokenType.STRING) {
                                throw new Error(`[Parser Error] Line ${this.peek().line}: String literal cannot be used as shorthand property`);
                            }
                            value = key; // Shorthand property
                        }
                        properties.push(key, value);
                    }
                } while (this.match(TokenType.PUNCTUATION, ','));
            }
            this.consume(TokenType.PUNCTUATION, "Expect '}' after object properties", '}');
            return this.node(Opcode.OBJECT, properties, startToken);
        }

        throw new Error(`[Parser Error] Line ${this.peek().line}: Expect expression. Found '${this.peek().value}'`);
    }

    private parseTemplateLiteral(str: string): OmniASTNode {
        const parts = [];
        let current = '';
        let i = 0;
        while (i < str.length) {
            if (str[i] === '$' && str[i+1] === '{') {
                if (current) parts.push(`"${current}"`);
                current = '';
                i += 2;

                let exprStr = '';
                let openBraces = 1;
                let inString = false;
                let stringQuote = '';

                while (i < str.length && openBraces > 0) {
                    const char = str[i];
                    if (!inString) {
                        if (char === '{') openBraces++;
                        else if (char === '}') openBraces--;
                        else if (char === '"' || char === "'" || char === '`') {
                            inString = true;
                            stringQuote = char;
                        }
                    } else {
                        if (char === stringQuote && str[i-1] !== '\\') {
                            inString = false;
                        }
                    }
                    if (openBraces > 0) exprStr += char;
                    i++;
                }
                if (openBraces > 0) throw new Error("[Parser Error] Unterminated template literal expression");
                parts.push(this.parseExpressionFromString(exprStr));
            } else {
                current += str[i];
                i++;
            }
        }
        if (current) parts.push(`"${current}"`);
        if (parts.length === 0) return '""';
        let expr = parts[0];
        for (let j = 1; j < parts.length; j++) {
            expr = this.node(Opcode.ADD, [expr, parts[j]]);
        }
        return expr;
    }

    protected parseExpressionFromString(str: string): OmniASTNode {
        throw new Error("Must be implemented by Parser");
    }

    protected block(): OmniASTNode[] {
        return (this as any).block();
    }
}

import { OmniAST, OmniASTNode, Opcode } from '../core/types';
import { TranspilerPart2 } from './transpiler_part2';

/**
 * cHams V5.5: THE AEGIS TRANSPILER (AOT COMPILATION TO JS/TS)
 * 
 * This class is the final entry point for transpilation.
 * It inherits from TranspilerPart2, which inherits from TranspilerPart1.
 */
export class Transpiler extends TranspilerPart2 {
    constructor(ast: OmniAST, isTypeScript: boolean = true) {
        super(ast, isTypeScript);
    }
}

/* eslint-disable no-useless-assignment */
import { Opcode, OmniAST, OmniASTNode } from '../core/types';

// ============================================================================
// cHams V5.5: THE AEGIS TRANSPILER (AOT COMPILATION TO JS/TS) - PART 1
// ============================================================================

export class TranspilerPart1 {
    protected ast: OmniAST;
    protected indentLevel: number = 0;
    protected isTypeScript: boolean;

    constructor(ast: OmniAST, isTypeScript: boolean = true) {
        this.ast = ast;
        this.isTypeScript = isTypeScript;
    }

    public transpile(): string {
        let code = '';
        for (const node of this.ast) {
            code += this.transpileNode(node) + ';\n';
        }

        this.postEmitValidation(code);
        return code;
    }

    protected postEmitValidation(code: string): void {
        // Structural identity check: ensure balanced braces and parentheses
        let braces = 0;
        let parens = 0;
        let brackets = 0;
        let inString = false;
        let stringQuote = '';

        for (let i = 0; i < code.length; i++) {
            const char = code[i];
            if (!inString) {
                if (char === '{') braces++;
                else if (char === '}') braces--;
                else if (char === '(') parens++;
                else if (char === ')') parens--;
                else if (char === '[') brackets++;
                else if (char === ']') brackets--;
                else if (char === '"' || char === "'" || char === '`') {
                    inString = true;
                    stringQuote = char;
                }
            } else {
                if (char === stringQuote && code[i-1] !== '\\') {
                    inString = false;
                }
            }
        }

        if (braces !== 0 || parens !== 0 || brackets !== 0) {
            throw new Error(`[Transpiler Error] Structural mismatch detected in generated code. Braces: ${braces}, Parens: ${parens}, Brackets: ${brackets}. Possible truncation.`);
        }
    }

    protected indent(): string {
        return '    '.repeat(this.indentLevel);
    }

    protected transpilePattern(pattern: any): string {
        if (typeof pattern === 'string') return pattern;
        if (pattern.type === "array") {
            return `[${pattern.elements.map((el: any) => {
                if (el.type === "rest") return `...${el.name}`;
                return this.transpilePattern(el);
            }).join(', ')}]`;
        }
        if (pattern.type === "object") {
            return `{${pattern.properties.map((prop: any) => {
                if (prop.type === "rest") return `...${prop.name}`;
                if (prop.key === prop.value) return prop.key;
                return `${prop.key}: ${this.transpilePattern(prop.value)}`;
            }).join(', ')}}`;
        }
        return String(pattern);
    }

    protected transpileNode(node: OmniASTNode): string {
        if (node === null) return 'null';
        if (node === undefined) return 'undefined';
        if (typeof node === 'string') return node;
        if (typeof node === 'number' || typeof node === 'boolean') return String(node);

        let opcode: Opcode;
        let args: any[];

        if (Array.isArray(node)) {
            if (typeof node[0] === 'number') {
                // Legacy Array Node
                opcode = node[0] as Opcode;
                args = node.slice(1);
            } else {
                // It's a block of nodes
                return node.map(n => this.transpileNode(n)).join(';\n');
            }
        } else if (typeof node === 'object' && 'type' in node) {
            // New Object Node
            opcode = node.type;
            args = node.args;
        } else {
            return '';
        }

        switch (opcode) {
            case Opcode.LET:
            case Opcode.CONST:
            case Opcode.REACTIVE: {
                const pattern = args[0];
                const init = args[1] ? this.transpileNode(args[1]) : undefined;
                const typeAnnotation = args[2] as string | null;
                const isConst = args[3] as boolean;
                const keyword = isConst ? 'const' : 'let';
                const isReactive = opcode === Opcode.REACTIVE;

                let typeStr = '';
                if (this.isTypeScript && typeAnnotation) {
                    typeStr = `: ${typeAnnotation}`;
                }

                const patternStr = this.transpilePattern(pattern);

                if (isReactive) {
                    return `let /* reactive */ ${patternStr}${typeStr}${init !== undefined ? ` = ${init}` : ''}`;
                }

                return `${keyword} ${patternStr}${typeStr}${init !== undefined ? ` = ${init}` : ''}`;
            }
            case Opcode.ASSIGN: {
                const name = args[0] as string;
                const value = this.transpileNode(args[1]);
                return `${name} = ${value}`;
            }
            case Opcode.ADD:
            case Opcode.SUB:
            case Opcode.MUL:
            case Opcode.DIV:
            case Opcode.MOD:
            case Opcode.EXP:
            case Opcode.EQ:
            case Opcode.NEQ:
            case Opcode.STRICT_EQ:
            case Opcode.STRICT_NEQ:
            case Opcode.GT:
            case Opcode.LT:
            case Opcode.GTE:
            case Opcode.LTE:
            case Opcode.AND:
            case Opcode.OR:
            case Opcode.BIT_OR:
            case Opcode.BIT_XOR:
            case Opcode.BIT_AND:
            case Opcode.BIT_LSHIFT:
            case Opcode.BIT_RSHIFT:
            case Opcode.NULLISH: {
                const opMap: Record<number, string> = {
                    [Opcode.ADD]: '+', [Opcode.SUB]: '-', [Opcode.MUL]: '*', [Opcode.DIV]: '/',
                    [Opcode.MOD]: '%', [Opcode.EXP]: '**', [Opcode.EQ]: '==', [Opcode.NEQ]: '!=',
                    [Opcode.STRICT_EQ]: '===', [Opcode.STRICT_NEQ]: '!==', [Opcode.GT]: '>',
                    [Opcode.LT]: '<', [Opcode.GTE]: '>=', [Opcode.LTE]: '<=', [Opcode.AND]: '&&',
                    [Opcode.OR]: '||', [Opcode.BIT_OR]: '|', [Opcode.BIT_XOR]: '^', [Opcode.BIT_AND]: '&',
                    [Opcode.BIT_LSHIFT]: '<<', [Opcode.BIT_RSHIFT]: '>>', [Opcode.NULLISH]: '??'
                };
                return `(${this.transpileNode(args[0])} ${opMap[opcode]} ${this.transpileNode(args[1])})`;
            }
            case Opcode.NOT: return `!(${this.transpileNode(args[0])})`;
            case Opcode.TYPEOF: return `typeof (${this.transpileNode(args[0])})`;
            case Opcode.SPREAD: return `...${this.transpileNode(args[0])}`;
            case Opcode.AWAIT: return `await ${this.transpileNode(args[0])}`;
            case Opcode.GET: return `${this.transpileNode(args[0])}[${this.transpileNode(args[1])}]`;
            case Opcode.OPTIONAL_CHAIN: return `${this.transpileNode(args[0])}?.${this.transpileNode(args[1]).replace(/^"|"$/g, '')}`;
            case Opcode.SET: return `${this.transpileNode(args[0])}[${this.transpileNode(args[1])}] = ${this.transpileNode(args[2])}`;
            case Opcode.CALL: {
                const callee = this.transpileNode(args[0]);
                const callArgs = args.slice(1).map(arg => this.transpileNode(arg)).join(', ');
                return `${callee}(${callArgs})`;
            }
            case Opcode.OS_CALL: {
                const funcName = args[0] as string;
                const callArgs = args.slice(1).map(arg => this.transpileNode(arg)).join(', ');
                return `OS.${funcName}(${callArgs})`;
            }
            case Opcode.NEW: {
                const expr = this.transpileNode(args[0]);
                return `new ${expr}`;
            }
            case Opcode.THIS: return 'this';
            case Opcode.SUPER: return 'super';
            case Opcode.ARRAY: {
                const elements = args.map(el => this.transpileNode(el)).join(', ');
                return `[${elements}]`;
            }
            case Opcode.OBJECT: {
                const props = [];
                for (let i = 0; i < args.length; i += 2) {
                    const key = args[i] as string | OmniASTNode;
                    if (typeof key === 'object' && key !== null && !Array.isArray(key) && 'type' in key && key.type === Opcode.SPREAD) {
                        props.push(`...${this.transpileNode(key.args[0])}`);
                    } else if (Array.isArray(key) && key[0] === Opcode.SPREAD) {
                        props.push(`...${this.transpileNode(key[1])}`);
                    } else {
                        const valNode = args[i + 1];
                        const value = this.transpileNode(valNode);
                        if (typeof key === 'string' && key === value) {
                            props.push(key);
                        } else {
                            props.push(`${key}: ${value}`);
                        }
                    }
                }
                return `{ ${props.join(', ')} }`;
            }
            case Opcode.TERNARY: {
                const cond = this.transpileNode(args[0]);
                const trueExpr = this.transpileNode(args[1]);
                const falseExpr = this.transpileNode(args[2]);
                return `(${cond} ? ${trueExpr} : ${falseExpr})`;
            }
            case Opcode.INC: {
                const target = this.transpileNode(args[0]);
                const isPrefix = args[1] as boolean;
                return isPrefix ? `++${target}` : `${target}++`;
            }
            case Opcode.DEC: {
                const target = this.transpileNode(args[0]);
                const isPrefix = args[1] as boolean;
                return isPrefix ? `--${target}` : `${target}--`;
            }
            case Opcode.PRINT: return `console.log(${this.transpileNode(args[0])})`;
            case Opcode.IF: {
                const cond = this.transpileNode(args[0]);
                let code = `if (${cond}) {\n`;
                this.indentLevel++;
                const thenBranch = args[1] as OmniASTNode[];
                for (const stmt of thenBranch) {
                    code += this.indent() + this.transpileNode(stmt) + ';\n';
                }
                this.indentLevel--;
                code += this.indent() + '}';

                if (args[2]) {
                    code += ' else {\n';
                    this.indentLevel++;
                    const elseBranch = args[2] as OmniASTNode[];
                    for (const stmt of elseBranch) {
                        code += this.indent() + this.transpileNode(stmt) + ';\n';
                    }
                    this.indentLevel--;
                    code += this.indent() + '}';
                }
                return code;
            }
            case Opcode.WHILE: {
                const cond = this.transpileNode(args[0]);
                let code = `while (${cond}) {\n`;
                this.indentLevel++;
                const body = args[1] as OmniASTNode[];
                for (const stmt of body) {
                    code += this.indent() + this.transpileNode(stmt) + ';\n';
                }
                this.indentLevel--;
                code += this.indent() + '}';
                return code;
            }
            case Opcode.FOR: {
                const init = args[0] ? this.transpileNode(args[0]) : '';
                const cond = args[1] ? this.transpileNode(args[1]) : '';
                const inc = args[2] ? this.transpileNode(args[2]) : '';
                let code = `for (${init}; ${cond}; ${inc}) {\n`;
                this.indentLevel++;
                const body = args[3] as OmniASTNode[];
                for (const stmt of body) {
                    code += this.indent() + this.transpileNode(stmt) + ';\n';
                }
                this.indentLevel--;
                code += this.indent() + '}';
                return code;
            }
            case Opcode.FOR_OF: {
                const varName = args[0] as string;
                const iterable = this.transpileNode(args[1]);
                const isConst = args[3] as boolean;
                const keyword = isConst ? 'const' : 'let';
                let code = `for (${keyword} ${varName} of ${iterable}) {\n`;
                this.indentLevel++;
                const body = args[2] as OmniASTNode[];
                for (const stmt of body) {
                    code += this.indent() + this.transpileNode(stmt) + ';\n';
                }
                this.indentLevel--;
                code += this.indent() + '}';
                return code;
            }
            case Opcode.FOR_IN: {
                const varName = args[0] as string;
                const obj = this.transpileNode(args[1]);
                const isConst = args[3] as boolean;
                const keyword = isConst ? 'const' : 'let';
                let code = `for (${keyword} ${varName} in ${obj}) {\n`;
                this.indentLevel++;
                const body = args[2] as OmniASTNode[];
                for (const stmt of body) {
                    code += this.indent() + this.transpileNode(stmt) + ';\n';
                }
                this.indentLevel--;
                code += this.indent() + '}';
                return code;
            }
            case Opcode.BREAK: return 'break';
            case Opcode.CONTINUE: return 'continue';
            case Opcode.RETURN: return `return ${args[0] ? this.transpileNode(args[0]) : ''}`;
            case Opcode.THROW: return `throw ${this.transpileNode(args[0])}`;
            default:
                return this.transpileNodePart2(opcode, args);
        }
    }

    protected transpileNodePart2(opcode: Opcode, args: any[]): string {
        // This method will be implemented in transpiler_part2.ts
        return '';
    }
}

