    OSRegistry['UI.Notify'] = async (message: string, type: string = 'info') => {
        // console.log(`[cHams Macro] OS.UI.Notify -> ${type.toUpperCase()}: ${message}`);

        if (typeof window !== 'undefined') {
            window.dispatchEvent(new CustomEvent('ham-os-notify', {
                detail: { message, type }
            }));
        }
        return true;
