            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
              {filteredDocs.length > 0 ? (
                <div className="grid grid-cols-1 gap-2">
                  {filteredDocs.map((doc) => (
