  activeClone: typeof CLONES[0],
  setLoadingProgress: (val: { progress: number; text: string } | null) => void,
  showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void,
  onUpdate?: (text: string) => void, 
  retries: string[] = [], 
  abortSignal?: AbortSignal
