export const useAIHubChat_Part1 = (props: any) => {
  const {
    saveMessageToDB,
    customInstruction,
    allInstructions,
    singularityMode,
    currentSessionId,
    setIsLoading,
    setLoadingProgress,
    setAbortController,
    setSummaryContext,
