    const isVoiceRequest = lowerMsg.includes('buatkan suara') || lowerMsg.includes('bikin suara') || lowerMsg.includes('bacakan') || lowerMsg.includes('voice over');

    if (isMusicRequest && userMsg.length < 50 && !isResume) {
