              {msg.audio && <MediaContainer type={isMusic ? 'music' : 'audio'} src={msg.audio} title={isMusic ? 'Music Player (Lyria Engine)' : 'Voice Audio'} />}
              {msg.video && <MediaContainer type="video" src={msg.video} />}

