import React, { useState, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import rehypeRaw from 'rehype-raw';
import rehypeSanitize from 'rehype-sanitize';
import remarkGfm from 'remark-gfm';
import { ThumbsUp, ThumbsDown, Sparkles, Loader2, Check, ImageOff, Trash2, ChevronDown, ChevronRight, Copy, AlertTriangle } from 'lucide-react';
import { ChatMessageData, ProjectData, AgentActivity, ProjectFile } from './types';
import CodeBlock from './CodeBlock';
import MultimodalContent from './MultimodalContent';
import StepTimeline from './StepTimeline';
import { useSmoothStream } from '../../hooks/useSmoothStream';
import { AdvancedAssistantUI } from './Assistant/AdvancedAssistantUI';

interface ChatMessageProps {
  message: ChatMessageData;
  isLoading?: boolean;
  isStreaming?: boolean;
  activities?: ChatMessageData['activities'];
  timer?: number;
  progress?: number;
  onCancel?: () => void;
  onFeedback?: (type: 'up' | 'down') => void;
  onRestore?: (project: ProjectData) => void;
  onViewChanges?: (project: ProjectData) => void;
  onFixError?: (errorMsg: string) => void;
  onIgnoreError?: (messageId: string) => void;
  isLast?: boolean;
  isBuildDisabled?: boolean;
  buildError?: string | null;
  selectedFile?: ProjectFile | null;
}

// Optimized Image Component with Error Handling
interface SafeImageProps extends React.ImgHTMLAttributes<HTMLImageElement> {}

const SafeImage = ({ src, alt, ...props }: SafeImageProps) => {
  const [error, setError] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center p-4 bg-red-500/10 border border-red-500/20 rounded-lg text-red-400 text-xs">
        <ImageOff size={20} className="mb-2" />
        <span>Failed to load image</span>
      </div>
    );
  }

  return (
    <div className="relative min-h-[100px] flex items-center justify-center bg-black/20 rounded-lg my-2">
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center">
          <Loader2 size={20} className="animate-spin text-blue-400" />
        </div>
      )}
      <img 
        src={src} 
        alt={alt} 
        onError={() => { setError(true); setIsLoading(false); }}
        onLoad={() => setIsLoading(false)}
        referrerPolicy="no-referrer"
        loading="lazy"
        className={`rounded-lg max-w-full h-auto border border-white/10 transition-opacity duration-300 ${isLoading ? 'opacity-0' : 'opacity-100'}`}
        {...props} 
      />
    </div>
  );
};

export default React.memo(function ChatMessage({ 
  message, isLoading, isStreaming, activities, timer, progress, 
  onCancel, onFeedback, onRestore, onViewChanges, onFixError, onIgnoreError,
  isBuildDisabled, buildError, selectedFile
}: ChatMessageProps) {
  const [feedbackGiven, setFeedbackGiven] = useState<'up' | 'down' | null>(message.feedback || null);
  const [isCopied, setIsCopied] = useState(false);
  const displayedContent = useSmoothStream(message.content, !!isStreaming);

  const handleCopyMessage = async () => {
    try {
      await navigator.clipboard.writeText(message.content);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    } catch (err) {
      // console.error('Failed to copy message:', err);
    }
  };

  const handleFeedback = (type: 'up' | 'down') => {
    setFeedbackGiven(type);
    if (onFeedback) {
        onFeedback(type);
        // Simulate toast/feedback
    }
  };

  // Memoize markdown components to prevent re-creation on every render
  const markdownComponents = useMemo(() => ({
    code({ node, inline, className, children, ...props }: any) {
      const match = /language-(\w+)/.exec(className || '');
      const content = String(children).replace(/\n$/, '');

      if (!inline && match) {
        // Try to extract filename from the first line comment
        const firstLine = content.split('\n')[0];
        const commentMatch = firstLine?.match(/^(?:\/\/|#|<!--|\/\*)\s*([\w./-]+\.\w+)\s*(?:-->|\*\/)?$/i);

        if (commentMatch) {
          const filePath = commentMatch[1];
          const isDelete = firstLine.toUpperCase().includes('DELETE');

          return (
            <div className={`my-2 p-3 bg-[#1e1e1e] border ${isDelete ? 'border-red-500/20' : 'border-white/10'} rounded-lg flex items-center justify-between group hover:border-blue-500/30 transition-all`}>
              <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-full ${isDelete ? 'bg-red-500/10 border-red-500/20' : 'bg-green-500/10 border-green-500/20'} flex items-center justify-center border`}>
                  {isDelete ? (
                    <Trash2 size={14} className="text-red-500" />
                  ) : (
                    <Check size={14} className="text-green-500" />
                  )}
                </div>
                <div className="flex flex-col">
                  <span className="text-xs font-bold text-gray-200">{filePath.split('/').pop()}</span>
                  <span className="text-[10px] text-gray-500 font-mono">{filePath}</span>
                </div>
              </div>
              <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                 <span className={`text-[10px] ${isDelete ? 'text-red-400 bg-red-500/10' : 'text-green-400 bg-green-500/10'} font-medium uppercase tracking-wider px-2 py-1 rounded`}>
                   {isDelete ? 'Deleted' : 'Updated'}
                 </span>
              </div>
            </div>
          );
        }

        // Fallback for code blocks without explicit file path (e.g. explanations)
        // The user requested to NOT show code in conversation if possible, but we should keep snippets that are not files.
        // However, if it looks like a file block but missed the regex, we might want to hide it too?
        // For now, let's render non-file blocks as collapsed or standard code blocks.
        return (
          <CodeBlock
            language={match[1]}
            value={content}
          />
        );
      }

      return (
        <code className={`${className} bg-black/20 px-1 py-0.5 rounded text-red-300 font-mono text-[0.9em]`} {...props}>
          {children}
        </code>
      );
    },
    img: SafeImage,
    a({ node, href, children, ...props }: any) {
      const url = href || '';
      if (url.match(/\.(mp4|webm|ogg)$/i)) {
        return <MultimodalContent type="video" url={url} />;
      }
      if (url.match(/\.(mp3|wav|ogg)$/i)) {
        return <MultimodalContent type="audio" url={url} />;
      }
      return <a href={href} className="text-blue-400 hover:underline break-all" target="_blank" rel="noopener noreferrer" {...props}>{children}</a>;
    },
    p: ({children}: {children: React.ReactNode}) => <p className="mb-2 last:mb-0">{children}</p>,
    ul: ({children}: {children: React.ReactNode}) => <ul className="list-disc pl-4 mb-2 space-y-1">{children}</ul>,
    ol: ({children}: {children: React.ReactNode}) => <ol className="list-decimal pl-4 mb-2 space-y-1">{children}</ol>,
    li: ({children}: {children: React.ReactNode}) => <li className="pl-1">{children}</li>,
    h1: ({children}: {children: React.ReactNode}) => <h1 className="text-xl font-bold mb-2 mt-4 text-white border-b border-white/10 pb-1">{children}</h1>,
    h2: ({children}: {children: React.ReactNode}) => <h2 className="text-lg font-bold mb-2 mt-3 text-white">{children}</h2>,
    h3: ({children}: {children: React.ReactNode}) => <h3 className="text-base font-bold mb-1 mt-2 text-white">{children}</h3>,
    blockquote: ({children}: {children: React.ReactNode}) => <blockquote className="border-l-4 border-blue-500/50 pl-4 italic text-gray-400 my-2 bg-blue-500/5 py-1 pr-2 rounded-r">{children}</blockquote>,
    table: ({children}: {children: React.ReactNode}) => <div className="overflow-x-auto my-2 rounded border border-white/10"><table className="min-w-full divide-y divide-white/10 text-sm">{children}</table></div>,
    thead: ({children}: {children: React.ReactNode}) => <thead className="bg-white/5">{children}</thead>,
    th: ({children}: {children: React.ReactNode}) => <th className="px-3 py-2 text-left text-xs font-medium text-gray-300 uppercase tracking-wider">{children}</th>,
    td: ({children}: {children: React.ReactNode}) => <td className="px-3 py-2 whitespace-nowrap text-gray-300 border-t border-white/5">{children}</td>,
    details: ({children}: {children: React.ReactNode}) => (
      <details className="group border border-white/10 rounded-lg my-2 bg-white/5 overflow-hidden transition-all">
        {children}
      </details>
    ),
    summary: ({children}: {children: React.ReactNode}) => (
      <summary className="px-4 py-2 cursor-pointer font-bold text-xs uppercase tracking-widest text-blue-400 hover:bg-white/5 list-none flex items-center gap-2">
        <ChevronRight size={14} className="group-open:rotate-90 transition-transform" />
        {children}
      </summary>
    ),
    pre: ({children}: {children: React.ReactNode}) => {
      const content = React.Children.toArray(children).join('');
      const isUnifiedContainer = content.includes('┌') || content.includes('│') || content.includes('└');

      return (
        <pre className={`${isUnifiedContainer ? 'bg-[#1a1a1a] border-blue-500/30 text-blue-300' : 'bg-[#0a0a0a] border-white/10'} border rounded-lg p-4 my-2 overflow-x-auto font-mono text-xs leading-relaxed shadow-inner`}>
          {children}
        </pre>
      );
    },
  }), []);

  const markdownContent = useMemo(() => (
    <ReactMarkdown 
      components={markdownComponents}
      rehypePlugins={[rehypeRaw, rehypeSanitize]}
      remarkPlugins={[remarkGfm]}
    >
      {displayedContent}
    </ReactMarkdown>
  ), [displayedContent, markdownComponents]);

  if (isLoading) {
    return (
      <div className="flex items-start gap-3 animate-in fade-in duration-300">
        <div className="w-6 h-6 bg-blue-500/10 rounded-full flex items-center justify-center border border-blue-500/20 shrink-0 shadow-lg shadow-blue-500/10">
          <Loader2 size={11} className="animate-spin text-blue-400" />
        </div>
        <div className="flex-1 pt-1 min-w-0">
          <div className="flex items-center justify-between mb-2">
            <h4 className="font-semibold text-sm text-[var(--text-secondary)] flex items-center gap-2">
              <Sparkles size={10} className="text-purple-400" />
              Ham AI Studio
            </h4>
            <div className="flex items-center gap-2">
              <div className="flex items-center gap-1.5 bg-[var(--bg-tertiary)] px-2 py-0.5 rounded-md border border-white/5">
                <span className="text-[10px] font-mono text-[var(--text-secondary)] uppercase tracking-wider">Progress:</span>
                <span className="text-[10px] font-mono text-amber-500">{progress}%</span>
              </div>
              <span className="text-[10px] font-mono text-[var(--text-secondary)] bg-[var(--bg-tertiary)] px-1.5 py-0.5 rounded-md border border-white/5">{Math.floor(timer)}s</span>
            </div>
          </div>

          {/* Render Step Timeline if available */}
          {message.steps && message.steps.length > 0 ? (
            <StepTimeline steps={message.steps} />
          ) : (
            <div className="space-y-2 bg-black/20 p-3 rounded-lg border border-white/5">
               <div className="text-xs text-[var(--text-secondary)]">Processing request...</div>
               <AdvancedAssistantUI 
                 activities={activities || []} 
                 selectedFile={selectedFile}
                 isBuildDisabled={isBuildDisabled}
                 buildError={buildError}
               />
            </div>
          )}
        </div>
      </div>
    );
  }

  if (message.role === 'user') {
    return (
      <div className="flex justify-end mb-4 group">
        <div className="bg-blue-600 text-white px-4 py-3 rounded-2xl rounded-tr-sm max-w-[85%] text-sm shadow-lg shadow-blue-500/20 break-words">
          <ReactMarkdown 
            components={markdownComponents}
            rehypePlugins={[rehypeRaw, rehypeSanitize]}
            remarkPlugins={[remarkGfm]}
          >
            {message.content}
          </ReactMarkdown>
        </div>
      </div>
    );
  }

  if (message.isError) {
    return (
      <div className="flex items-start gap-3 mb-4 group animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="w-6 h-6 bg-red-500/20 rounded-full flex items-center justify-center border border-red-500/30 shrink-0 shadow-lg shadow-red-500/10 mt-1">
          <AlertTriangle size={11} className="text-red-400" />
        </div>
        <div className="flex-1 min-w-0">
          <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-4">
            <h4 className="text-red-400 font-semibold text-sm mb-2 flex items-center gap-2">
              <AlertTriangle size={12} />
              Preview Error Detected
            </h4>
            <div className="text-red-300/80 text-xs font-mono whitespace-pre-wrap break-words mb-4 bg-black/20 p-2 rounded">
              {message.content}
            </div>
            <div className="flex items-center gap-2">
              {onFixError && (
                <button 
                  onClick={() => onFixError(message.content)}
                  className="px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white rounded-md text-xs font-medium transition-colors shadow-lg shadow-blue-500/20"
                >
                  Fix Error
                </button>
              )}
              {onIgnoreError && (
                <button 
                  onClick={() => onIgnoreError(message.id!)}
                  className="px-3 py-1.5 bg-white/5 hover:bg-white/10 text-[var(--text-secondary)] hover:text-white rounded-md text-xs font-medium transition-colors"
                >
                  Ignore
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex items-start gap-3 mb-4 group animate-in fade-in slide-in-from-bottom-2 duration-300">
      <div className="w-6 h-6 bg-gradient-to-br from-blue-500/20 to-purple-500/20 rounded-full flex items-center justify-center border border-blue-500/30 shrink-0 shadow-lg shadow-blue-500/10 mt-1">
        <Sparkles size={11} className="text-blue-400" />
      </div>
      <div className="flex-1 min-w-0">
        {/* Render Steps History if available */}
        {message.steps && message.steps.length > 0 && (
          <div className="mb-4 border-b border-white/5 pb-4">
            <StepTimeline steps={message.steps} />
          </div>
        )}

        <div className="prose prose-sm prose-zinc prose-invert max-w-none leading-relaxed select-text">
          {markdownContent}
        </div>

        {message.projectSnapshot && (
          <div className="mt-4 border border-[var(--border-color)] rounded-lg p-3 bg-[var(--bg-tertiary)]/50 flex items-center justify-between backdrop-blur-sm">
            <div className="flex items-center gap-2 text-xs text-[var(--text-secondary)]">
                <div className="w-5 h-5 rounded-full bg-green-500/20 flex items-center justify-center border border-green-500/30">
                  <Check size={10} className="text-green-500" />
                </div>
                <span className="font-medium">Project Updated</span>
            </div>
            <div className="flex items-center gap-2">
                {onViewChanges && (
                  <button onClick={() => onViewChanges(message.projectSnapshot!)} className="px-3 py-1.5 rounded-md text-[10px] font-bold uppercase tracking-wider bg-[var(--bg-secondary)] hover:bg-[var(--bg-primary)] text-[var(--text-primary)] border border-[var(--border-color)] transition-all hover:border-blue-500/50">
                    View Changes
                  </button>
                )}
                {onRestore && (
                  <button onClick={() => onRestore(message.projectSnapshot!)} className="px-3 py-1.5 rounded-md text-[10px] font-bold uppercase tracking-wider bg-[var(--bg-secondary)] hover:bg-[var(--bg-primary)] text-[var(--text-primary)] border border-[var(--border-color)] transition-all hover:border-blue-500/50">
                    Restore Version
                  </button>
                )}
            </div>
          </div>
        )}

        <div className="flex items-center gap-2 mt-2 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
          <button 
            onClick={handleCopyMessage} 
            className="text-[var(--text-secondary)] hover:text-blue-400 hover:bg-white/5 p-1.5 rounded-md transition-all"
            title="Copy Message"
          >
            {isCopied ? <Check size={12} className="text-green-400" /> : <Copy size={12} />}
          </button>
          {onFeedback && (
            <>
              <button 
                onClick={() => handleFeedback('up')} 
                className={`${feedbackGiven === 'up' ? 'text-blue-400 bg-blue-500/10' : 'text-[var(--text-secondary)] hover:text-blue-400 hover:bg-white/5'} p-1.5 rounded-md transition-all`}
                title="Helpful"
              >
                <ThumbsUp size={12} />
              </button>
              <button 
                onClick={() => handleFeedback('down')} 
                className={`${feedbackGiven === 'down' ? 'text-red-400 bg-red-500/10' : 'text-[var(--text-secondary)] hover:text-red-400 hover:bg-white/5'} p-1.5 rounded-md transition-all`}
                title="Not Helpful"
              >
                <ThumbsDown size={12} />
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}, (prevProps, nextProps) => {
  if (nextProps.isStreaming) return false;

  return (
    prevProps.message.content === nextProps.message.content &&
    prevProps.message.steps?.length === nextProps.message.steps?.length &&
    prevProps.isLoading === nextProps.isLoading &&
    prevProps.timer === nextProps.timer &&
    prevProps.progress === nextProps.progress &&
    prevProps.activities?.length === nextProps.activities?.length
  );
});

/* eslint-disable no-useless-assignment */
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MessageSquare, Play, Layout, LayoutDashboard, Trash2, Sparkles, ChevronDown, Clock } from 'lucide-react';
import { Virtuoso, VirtuosoHandle } from 'react-virtuoso';
import ChatMessage from './ChatMessage';
import ChatInput from './ChatInput';
import NeuralNetworkVisualizer from './NeuralNetworkVisualizer';
import { ChatMessageData, ProjectData, AgentActivity } from './types';
import { safeStorage } from '../../utils/storage';
import { useConfirm } from '../../context/ConfirmContext';

interface ChatViewProps {
  isSplitView: boolean;
  isLoading: boolean;
  history: ChatMessageData[];
  agentActivities: AgentActivity[];
  timer: number;
  progress: number;
  input: string;
  setInput: (value: string) => void;
  handleSend: (e?: React.FormEvent, promptOverride?: string) => void;
  showSuggestions: boolean;
  handleSuggestionClick: (text: string) => void;
  handleMicClick: () => void;
  handleAttachClick: () => void;
  handlePlanningClick?: () => void;
  handleManualPlanningClick?: () => void;
  handleManualInstructionClick?: () => void;
  handleFileChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  fileInputRef: React.RefObject<HTMLInputElement>;
  setShowSuggestions: React.Dispatch<React.SetStateAction<boolean>>;
  messagesEndRef: React.RefObject<HTMLDivElement>;
  handleRestore: (project: ProjectData) => void;
  handleViewChanges: (project: ProjectData) => void;
  handleCancel: () => void;
  activeView: 'chat' | 'preview' | 'dashboard';
  setActiveView: (view: 'chat' | 'preview' | 'dashboard') => void;
  isMobile: boolean;
  setIsSplitView: (isSplit: boolean) => void;
  isLocalMode: boolean;
  setIsLocalMode: (isLocal: boolean) => void;
  setIsHistoryOpen: (isOpen: boolean) => void;
  isBuildDisabled?: boolean;
  buildError?: string | null;
  selectedFile?: any;
}

import { useProjectStore } from '../../store/projectStore';

export default function ChatView({
  isSplitView, isLoading, history, agentActivities, timer, progress, input, setInput, handleSend,
  showSuggestions, handleSuggestionClick, handleMicClick, handleAttachClick, handlePlanningClick, handleManualPlanningClick, handleManualInstructionClick, handleFileChange,
  fileInputRef, setShowSuggestions, messagesEndRef,
  handleRestore, handleViewChanges, handleCancel, activeView, setActiveView, isMobile, setIsSplitView,
  isLocalMode, setIsLocalMode, setIsHistoryOpen,
  isBuildDisabled, buildError, selectedFile
}: ChatViewProps) {
  const virtuosoRef = useRef<VirtuosoHandle>(null);
  const [engineName, setEngineName] = useState('Ham Engine Quantum');
  const [isEngineDropdownOpen, setIsEngineDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const { confirm } = useConfirm();
  const setHistory = useProjectStore(state => state.setHistory);

  const handleFixError = useCallback((errorMsg: string) => {
    handleSend(undefined, `Tolong perbaiki error berikut:\n\n${errorMsg}`);
  }, [handleSend]);

  const handleIgnoreError = useCallback((messageId: string) => {
    setHistory(prev => prev.filter(msg => msg.id !== messageId));
  }, [setHistory]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsEngineDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleEngineSelect = (modelId: string) => {
    safeStorage.setItem('ham_ai_model', modelId);
    setIsEngineDropdownOpen(false);
    setEngineName('Ham Agentic Shadow');
  };

  useEffect(() => {
    const updateEngineName = () => {
      setEngineName('Ham Agentic Shadow');
    };

    updateEngineName();
    const interval = setInterval(updateEngineName, 2000);
    return () => clearInterval(interval);
  }, []);

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    let timeoutId: NodeJS.Timeout;
    if (history.length > 0) {
      // Small delay to ensure rendering is done
      timeoutId = setTimeout(() => {
        virtuosoRef.current?.scrollToIndex({ index: history.length - 1, align: 'end', behavior: 'smooth' });
      }, 100);
    }
    return () => {
      if (timeoutId) clearTimeout(timeoutId);
    };
  }, [history.length, isLoading]);

  // Internal Timer Logic removed as it's now handled by parent hook

  const virtuosoContext = React.useMemo(() => ({
    isLoading,
    agentActivities,
    timer,
    progress,
    handleCancel,
    isBuildDisabled,
    buildError,
    selectedFile
  }), [isLoading, agentActivities, timer, progress, handleCancel, isBuildDisabled, buildError, selectedFile]);

  const VirtuosoFooter = useCallback(({ context }: any) => (
    <div className="pb-4">
      {context.isLoading && (
        <div className="px-3 md:px-4 py-2">
          <ChatMessage 
            message={{ role: 'ai', content: '' }} 
            isLoading={true} 
            activities={context.agentActivities} 
            timer={context.timer}
            progress={context.progress}
            onCancel={context.handleCancel}
            onFixError={handleFixError}
            onIgnoreError={handleIgnoreError}
            isBuildDisabled={context.isBuildDisabled}
            buildError={context.buildError}
            selectedFile={context.selectedFile}
          />
        </div>
      )}
      <div ref={messagesEndRef} />
    </div>
  ), [handleFixError, handleIgnoreError, messagesEndRef]);

  const virtuosoComponents = React.useMemo(() => ({
    Footer: VirtuosoFooter
  }), [VirtuosoFooter]);

  const handleClearChat = async () => {
    if (await confirm('Are you sure you want to clear the chat history?')) {
      // We need a way to clear history. We can do it by passing a clearHistory function or just setting history to [] if we have the setter.
      // But we don't have setHistory here. We can dispatch an event or add a prop.
      // For now, let's dispatch a custom event that MainContent or StudioSidebar can listen to.
      window.dispatchEvent(new CustomEvent('ham-clear-chat'));
    }
  };

  return (
    <div className={`flex-1 flex flex-col bg-[var(--bg-primary)] overflow-hidden relative ${isSplitView ? 'border-r border-[var(--border-color)]' : ''}`}>
      {isLoading && <NeuralNetworkVisualizer />}

      {/* Header */}
      <div className="flex items-center justify-between px-6 py-3 border-b border-[var(--border-color)] bg-[var(--bg-secondary)]/50 backdrop-blur-sm z-20">
        <div className="relative" ref={dropdownRef}>
          <div className="flex items-center gap-3 bg-[var(--bg-tertiary)] px-3 py-2 rounded border border-blue-500/20">
            <Sparkles size={16} className="text-blue-400 animate-pulse" />
            <span className="text-sm font-semibold text-[var(--text-primary)] uppercase tracking-wider">Super Assistant (Ham Agentic Shadow)</span>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {history.length > 0 && (
            <button 
              onClick={handleClearChat}
              className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-[var(--text-secondary)] hover:text-red-400 hover:bg-red-500/10 rounded transition-colors"
              title="Clear Chat History"
            >
              <Trash2 size={14} />
              Clear
            </button>
          )}
          <button 
            onClick={() => setIsHistoryOpen(true)}
            className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-[var(--text-secondary)] hover:text-blue-400 hover:bg-blue-500/10 rounded transition-colors"
            title="Restore Version / History"
          >
            <Clock size={14} />
            Restore Version
          </button>
        </div>
      </div>

      <div className="flex-1 min-h-0 relative z-10">
        {history.length === 0 && !isLoading ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
            <div className="w-20 h-20 bg-blue-500/10 rounded-full flex items-center justify-center mb-6 border border-blue-500/20 shadow-lg shadow-blue-500/5">
              <Sparkles size={36} className="text-blue-400" />
            </div>
            <h3 className="text-xl font-bold text-[var(--text-primary)] mb-3">How can I help you today?</h3>
            <p className="text-base text-[var(--text-secondary)] max-w-lg">
              I'm Ham Engine Singularity, your AI coding assistant. I can build apps, fix bugs, explain code, and help you design your project.
            </p>
          </div>
        ) : (
          <Virtuoso
            ref={virtuosoRef}
            style={{ height: '100%' }}
            data={history}
            context={virtuosoContext}
            followOutput={'auto'}
            itemContent={(index, msg) => (
              <div className="px-4 md:px-6 py-3">
                <ChatMessage 
                  key={msg.id || index} 
                  message={msg} 
                  isStreaming={isLoading && index === history.length - 1 && msg.role === 'ai'}
                  onRestore={handleRestore}
                  onViewChanges={handleViewChanges}
