import React, { useEffect, useState, useCallback } from 'react';
import { Package, Search, Download, Trash2, ExternalLink, Loader2, Check, AlertCircle, Play, Layers } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';
import { ProjectData } from '../types';
import { useConfirm } from '../../../context/ConfirmContext';

interface PackageManagerProps {
  project: ProjectData | null;
  onInstall: (pkg: string) => void;
  onUninstall: (pkg: string) => void;
  onRunScript?: (scriptName: string) => void;
}

interface NpmPackage {
  name: string;
  version: string;
  description: string;
  isDev?: boolean;
}

export default function PackageManager({ project, onInstall, onUninstall, onRunScript }: PackageManagerProps) {
  const [inputValue, setInputValue] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<NpmPackage[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [installedPackages, setInstalledPackages] = useState<NpmPackage[]>([]);
  const [npmScripts, setNpmScripts] = useState<Record<string, string>>({});
  const [installingPackages, setInstallingPackages] = useState<Set<string>>(new Set());
  const [parseError, setParseError] = useState<string | null>(null);
  const { confirm } = useConfirm();

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setSearchQuery(inputValue);
    }, 500);
    return () => clearTimeout(timer);
  }, [inputValue]);

  const handleInstall = async (pkgName: string) => {
    if (installingPackages.has(pkgName)) return;
    setInstallingPackages(prev => {
        const next = new Set(prev);
        next.add(pkgName);
        return next;
    });
    try {
        await onInstall(pkgName);
    } finally {
        setInstallingPackages(prev => {
            const next = new Set(prev);
            next.delete(pkgName);
            return next;
        });
    }
  };

  const handleUninstall = async (pkgName: string) => {
    if (installingPackages.has(pkgName)) return;
    if (!(await confirm(`Are you sure you want to uninstall ${pkgName}?`))) return;

    setInstallingPackages(prev => {
        const next = new Set(prev);
        next.add(pkgName);
        return next;
    });
    try {
        await onUninstall(pkgName);
    } finally {
        setInstallingPackages(prev => {
            const next = new Set(prev);
            next.delete(pkgName);
            return next;
        });
    }
  };

  const isPackageInstalled = (pkgName: string) => {
    return installedPackages.some(p => p.name === pkgName);
  };

  useEffect(() => {
    if (project) {
      const pkgJsonFile = project.files.find(f => f.path === 'package.json');
      if (pkgJsonFile) {
        try {
          const pkgJson = JSON.parse(pkgJsonFile.content);
          const deps = Object.entries(pkgJson.dependencies || {}).map(([name, version]) => ({
            name,
            version: version as string,
            description: 'Dependency',
            isDev: false
          }));
          const devDeps = Object.entries(pkgJson.devDependencies || {}).map(([name, version]) => ({
            name,
            version: version as string,
            description: 'Dev Dependency',
            isDev: true
          }));

          setInstalledPackages([...deps, ...devDeps]);

          if (pkgJson.scripts) {
            setNpmScripts(pkgJson.scripts);
          } else {
            setNpmScripts({});
          }
          setParseError(null);
        } catch (e) {
          console.error("Failed to parse package.json", e);
          setParseError("Invalid package.json file. Please fix syntax errors.");
          setInstalledPackages([]);
          setNpmScripts({});
        }
      } else {
          setInstalledPackages([]);
          setNpmScripts({});
          setParseError(null);
      }
    }
  }, [project]);

  useEffect(() => {
    const search = async () => {
        if (!searchQuery.trim()) {
            setSearchResults([]);
            return;
        }
        setIsSearching(true);
        try {
          // Use npms.io API for search
          const response = await fetch(`https://api.npms.io/v2/search?q=${encodeURIComponent(searchQuery)}`);
          if (!response.ok) throw new Error('Search failed');
          const data = await response.json();
          const results = data.results.map((r: any) => ({
            name: r.package.name,
            version: r.package.version,
            description: r.package.description
          }));
          setSearchResults(results);
        } catch (e) {
          console.error("NPM Search Error", e);
        } finally {
          setIsSearching(false);
        }
    };
    search();
  }, [searchQuery]);

  return (
    <div className="flex flex-col h-full bg-[#0a0a0a] text-xs font-mono">
      <div className="p-3 border-b border-white/10 bg-[#141414]">
        <h3 className="text-sm font-bold text-gray-200 mb-2 flex items-center gap-2">
          <Package size={16} className="text-blue-400" />
          Package Manager
        </h3>
        <div className="relative">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            placeholder="Search NPM packages..."
            className="w-full bg-[#050505] border border-white/10 rounded-md py-1.5 pl-8 pr-3 text-gray-300 focus:outline-none focus:border-blue-500/50"
          />
          <Search size={14} className="absolute left-2.5 top-2 text-gray-500" />
          {isSearching && <Loader2 size={14} className="absolute right-2.5 top-2 text-blue-500 animate-spin" />}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-3 space-y-4">
        {parseError && (
            <div className="bg-red-500/10 border border-red-500/20 p-3 rounded-lg flex items-start gap-2 text-red-400">
                <AlertCircle size={16} className="shrink-0 mt-0.5" />
                <div>
                    <p className="font-bold">Error parsing package.json</p>
                    <p className="opacity-80">{parseError}</p>
                </div>
            </div>
        )}

        {/* Search Results */}
        {searchResults.length > 0 && (
          <div>
            <h4 className="text-[10px] uppercase tracking-wider text-gray-500 font-bold mb-2">Search Results</h4>
            <div className="space-y-2">
              {searchResults.map((pkg) => (
                <div key={pkg.name} className="bg-[#1e1e1e] border border-white/5 rounded-lg p-3 flex items-center justify-between group hover:border-blue-500/30 transition-all">
                  <div className="flex-1 min-w-0 mr-3">
                    <div className="flex items-center gap-2">
                      <span className="font-bold text-blue-400 truncate">{pkg.name}</span>
                      <span className="text-[10px] bg-white/5 px-1.5 py-0.5 rounded text-gray-400">{pkg.version}</span>
                    </div>
                    <p className="text-gray-500 truncate mt-0.5">{pkg.description}</p>
                  </div>
                  <div className="flex gap-1">
                    <button
                        onClick={() => handleInstall(pkg.name)}
                        disabled={isPackageInstalled(pkg.name) || installingPackages.has(pkg.name)}
                        className={`p-1.5 rounded-md transition-colors ${
                            isPackageInstalled(pkg.name) 
                            ? 'bg-green-500/20 text-green-400 cursor-default' 
                            : 'bg-blue-600/20 text-blue-400 hover:bg-blue-600 hover:text-white'
                        }`}
                        title={isPackageInstalled(pkg.name) ? "Installed" : "Install Dependency"}
                    >
                        {installingPackages.has(pkg.name) ? (
                            <Loader2 size={14} className="animate-spin" />
                        ) : isPackageInstalled(pkg.name) ? (
                            <Check size={14} />
                        ) : (
                            <Download size={14} />
                        )}
                    </button>
                    {!isPackageInstalled(pkg.name) && !installingPackages.has(pkg.name) && (
                        <button
                            onClick={() => handleInstall(pkg.name + ' -D')}
                            className="p-1.5 rounded-md bg-yellow-600/20 text-yellow-400 hover:bg-yellow-600 hover:text-white transition-colors"
                            title="Install as Dev Dependency"
                        >
                            <span className="text-[10px] font-bold">DEV</span>
                        </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* NPM Scripts - Only show if not searching */}
        {!searchQuery && Object.keys(npmScripts).length > 0 && (
          <div className="mb-4">
            <h4 className="text-[10px] uppercase tracking-wider text-gray-500 font-bold mb-2">NPM Scripts</h4>
            <div className="space-y-1.5">
              {Object.entries(npmScripts).map(([name, cmd]) => (
                <div key={name} className="bg-[#1e1e1e] border border-white/5 rounded-lg p-2 flex items-center justify-between group hover:border-orange-500/30 transition-all">
                  <div className="flex-1 min-w-0 mr-2">
                    <span className="font-bold text-orange-400 text-xs">{name}</span>
                    <p className="text-gray-500 text-[9px] truncate font-mono mt-0.5" title={cmd}>{cmd}</p>
                  </div>
                  <button
                    onClick={() => onRunScript && onRunScript(name)}
                    className="p-1.5 bg-orange-600/20 text-orange-400 rounded-md hover:bg-orange-600 hover:text-white transition-colors"
                    title={`Run npm run ${name}`}
                  >
                    <Play size={12} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Installed Packages - Only show if not searching */}
        {!searchQuery && (
            <div>
            <h4 className="text-[10px] uppercase tracking-wider text-gray-500 font-bold mb-2">Installed Dependencies</h4>
            {installedPackages.length === 0 && !parseError ? (
                <p className="text-gray-600 italic text-center py-4">No packages installed yet.</p>
            ) : (
                <div className="space-y-2">
                {installedPackages.map((pkg) => (
                    <div key={pkg.name} className="bg-[#1e1e1e] border border-white/5 rounded-lg p-3 flex items-center justify-between group">
                    <div className="flex-1 min-w-0 mr-3">
                        <div className="flex items-center gap-2">
                        <span className={`font-bold truncate ${pkg.isDev ? 'text-yellow-400' : 'text-green-400'}`}>{pkg.name}</span>
                        <span className="text-[10px] bg-white/5 px-1.5 py-0.5 rounded text-gray-400">{pkg.version}</span>
                        {pkg.isDev && <span className="text-[9px] border border-yellow-500/30 text-yellow-500/70 px-1 rounded">dev</span>}
                        </div>
                    </div>
                    <button
                        onClick={() => handleUninstall(pkg.name)}
                        disabled={installingPackages.has(pkg.name)}
                        className="p-1.5 text-gray-500 hover:text-red-400 hover:bg-red-500/10 rounded-md transition-colors opacity-0 group-hover:opacity-100"
                        title="Uninstall"
                    >
                        {installingPackages.has(pkg.name) ? <Loader2 size={14} className="animate-spin" /> : <Trash2 size={14} />}
                    </button>
                    </div>
                ))}
                </div>
            )}
            </div>
        )}
      </div>
    </div>
  );
}

/* eslint-disable no-useless-assignment */
import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { X, Download, Cloud, Smartphone, FileCode, AlertTriangle, CheckCircle, Loader2, CheckSquare, Square, ArrowLeft } from 'lucide-react';
import { ProjectData } from './types';

interface ProjectExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  project: ProjectData | null;
  onExport: (type: 'zip' | 'apk', selectedFiles?: Set<string>) => void;
  isExporting: boolean;
  buildStatus?: 'idle' | 'building' | 'success' | 'error';
  onReset?: () => void;
  logs: string[];
}

export default function ProjectExportModal({
  isOpen,
  onClose,
  project,
  onExport,
  isExporting,
  buildStatus = 'idle',
  onReset,
  logs
}: ProjectExportModalProps) {
  const [step, setStep] = useState<'select' | 'configure-zip'>('select');
  const [selectedFiles, setSelectedFiles] = useState<Set<string>>(new Set());
  const logContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && project && !isExporting && buildStatus === 'idle') {
      setStep('select');
      setSelectedFiles(new Set((project.files || []).map(f => f.path)));
    }
  }, [isOpen, project, isExporting, buildStatus]);

  useEffect(() => {
    if (logContainerRef.current) {
      logContainerRef.current.scrollTop = logContainerRef.current.scrollHeight;
    }
  }, [logs]);

  const toggleFile = (path: string) => {
    const newSet = new Set(selectedFiles);
    if (newSet.has(path)) {
      newSet.delete(path);
    } else {
      newSet.add(path);
    }
    setSelectedFiles(newSet);
  };

  const toggleSelectAll = () => {
    if (!project || !project.files) return;
    if (selectedFiles.size === project.files.length) {
      setSelectedFiles(new Set());
    } else {
      setSelectedFiles(new Set(project.files.map(f => f.path)));
    }
  };

  const handleZipExport = () => {
    onExport('zip', selectedFiles);
  };

  const remoteBuildUrl = (import.meta as any).env.VITE_REMOTE_BUILD_URL;
  const isCloudBuildAvailable = !!remoteBuildUrl;

  const allSelected = project && project.files && selectedFiles.size === project.files.length;

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="bg-[#1e1e1e] border border-white/10 rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[80vh]"
          >
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b border-white/10 bg-[#252526]">
              <div className="flex items-center gap-2">
                {step === 'configure-zip' && !isExporting && (
                  <button 
                    onClick={() => setStep('select')}
                    className="mr-2 p-1 hover:bg-white/10 rounded-full transition-colors"
                  >
                    <ArrowLeft size={18} className="text-white/70" />
                  </button>
                )}
                <Download className="text-blue-400" size={20} />
                <h2 className="text-lg font-semibold text-white">
                  {step === 'configure-zip' ? 'Configure ZIP Export' : 'Export Project'}
                </h2>
              </div>
              <button
                onClick={onClose}
                className="p-1 hover:bg-white/10 rounded-lg transition-colors text-white/60 hover:text-white"
              >
                <X size={20} />
              </button>
            </div>

            {/* Content */}
            <div className="p-6 overflow-y-auto flex-1">
              {isExporting || buildStatus === 'building' || buildStatus === 'success' || buildStatus === 'error' ? (
                <div className="flex flex-col h-full">
                  <div className="flex items-center gap-3 mb-4">
                    {buildStatus === 'building' || isExporting ? (
                      <>
                        <Loader2 size={20} className="animate-spin text-blue-400" />
                        <span className="text-sm font-mono text-white/80">Processing export...</span>
                      </>
                    ) : buildStatus === 'success' ? (
                      <>
                        <CheckCircle size={20} className="text-green-400" />
                        <span className="text-sm font-mono text-white/80">Export Successful!</span>
                      </>
                    ) : (
                      <>
                        <AlertTriangle size={20} className="text-red-400" />
                        <span className="text-sm font-mono text-white/80">Export Failed</span>
                      </>
                    )}
                  </div>

                  <div 
                    ref={logContainerRef}
                    className="flex-1 bg-black/50 rounded-lg border border-white/10 p-3 font-mono text-xs overflow-y-auto min-h-[200px]"
                  >
                    {logs.map((log, i) => (
                      <div key={i} className="mb-1 break-all">
                        <span className="text-white/30 mr-2">[{new Date().toLocaleTimeString()}]</span>
                        <span className={
                          log.includes('ERROR') ? 'text-red-400' :
                          log.includes('SUCCESS') ? 'text-green-400' :
                          log.includes('WARN') ? 'text-yellow-400' :
                          'text-white/70'
                        }>
                          {log}
                        </span>
                      </div>
                    ))}
                  </div>

                  {buildStatus !== 'building' && !isExporting && (
                    <div className="mt-4 flex justify-end">
                      <button
                        onClick={() => {
                          if (onReset) onReset();
                          setStep('select');
                        }}
                        className="px-4 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-sm text-white transition-colors"
                      >
                        Back to Options
                      </button>
                    </div>
                  )}
                </div>
              ) : step === 'select' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Option 1: Source Code (ZIP) */}
                  <button
                    onClick={() => setStep('configure-zip')}
                    className="flex flex-col items-start gap-3 p-4 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 hover:border-blue-500/50 transition-all group text-left"
                  >
                    <div className="w-10 h-10 rounded-full bg-blue-500/20 flex items-center justify-center group-hover:scale-110 transition-transform">
                      <FileCode size={20} className="text-blue-400" />
                    </div>
                    <div>
                      <h3 className="font-semibold text-white">Source Code (ZIP)</h3>
                      <p className="text-xs text-white/50 mt-1">
                        Download full source code compatible with Android Studio or VS Code.
                      </p>
                    </div>
                  </button>

                  {/* Option 2: Native APK (Conditional) */}
                  <button
                    onClick={() => onExport('apk')}
                    className="flex flex-col items-start gap-3 p-4 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 hover:border-green-500/50 transition-all group text-left"
                  >
                    <div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center group-hover:scale-110 transition-transform">
                      <Smartphone size={20} className="text-green-400" />
                    </div>
                    <div>
                      <h3 className="font-semibold text-white">Build Native APK</h3>
                      <p className="text-xs text-white/50 mt-1">
                        Build debug APK using local native toolchain (if available).
                      </p>
                    </div>
                  </button>

                  {/* Option 3: Cloud Build */}
                  <button
                    onClick={() => isCloudBuildAvailable && onExport('apk')}
                    disabled={!isCloudBuildAvailable}
                    className={`flex flex-col items-start gap-3 p-4 rounded-xl bg-white/5 border border-white/10 transition-all group text-left ${isCloudBuildAvailable ? 'hover:bg-white/10 hover:border-purple-500/50' : 'opacity-60 cursor-not-allowed'}`}
                  >
                    <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center group-hover:scale-110 transition-transform">
                      <Cloud size={20} className="text-purple-400" />
                    </div>
                    <div>
                      <h3 className="font-semibold text-white">Cloud Build</h3>
                      <p className="text-xs text-white/50 mt-1">
                        {isCloudBuildAvailable 
                          ? "Build APK using remote build server." 
                          : "Remote build server is currently unavailable. Please use Source Code export."}
                      </p>
                    </div>
                  </button>
                </div>
              ) : (
                // Configure ZIP Step
                <div className="flex flex-col h-full">
                  <div className="mb-4 shrink-0">
                    <p className="text-sm text-white/70">Select files to include in the zip archive.</p>
                  </div>

                  <div className="flex-1 overflow-y-auto border border-white/10 rounded-lg bg-black/20 mb-4">
                    <div 
                        onClick={toggleSelectAll}
                        className="flex items-center gap-2 p-2 border-b border-white/10 hover:bg-white/5 cursor-pointer sticky top-0 bg-[#1e1e1e] z-10"
                    >
                        {allSelected ? <CheckSquare size={16} className="text-blue-400" /> : <Square size={16} className="text-white/50" />}
                        <span className="text-xs font-medium text-white">Select All ({(project?.files || []).length} files)</span>
                    </div>

                    <div className="p-1">
                        {(project?.files || []).map((file) => (
                            <div 
                                key={file.path}
                                onClick={() => toggleFile(file.path)}
                                className="flex items-center gap-2 p-1.5 hover:bg-white/5 rounded cursor-pointer"
                            >
                                {selectedFiles.has(file.path) ? <CheckSquare size={14} className="text-blue-400" /> : <Square size={14} className="text-white/50" />}
                                <FileCode size={14} className="text-white/50" />
                                <span className="text-xs text-white/90 truncate">{file.path}</span>
                            </div>
                        ))}
                    </div>
                  </div>

                  <button 
                    onClick={handleZipExport}
                    disabled={selectedFiles.size === 0}
                    className="w-full px-3 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-500 rounded-lg transition-colors flex items-center justify-center gap-2 shadow-lg shadow-blue-500/20 disabled:bg-gray-600 disabled:cursor-not-allowed shrink-0"
                  >
                    <Download size={18} />
                    Download .zip ({selectedFiles.size} files)
                  </button>
                </div>
              )}
            </div>

            {/* Footer */}
            <div className="p-4 border-t border-white/10 bg-[#252526] flex justify-end">
              <button
                onClick={onClose}
                disabled={isExporting}
                className="px-4 py-2 rounded-lg text-sm font-medium text-white/70 hover:text-white hover:bg-white/10 transition-colors disabled:opacity-50"
              >
                Close
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

/* eslint-disable no-useless-assignment */
import React, { useState, useEffect, useRef } from 'react';
import { X, Folder, Clock, Trash2, Plus, Maximize2, Play, Upload } from 'lucide-react';
import JSZip from 'jszip';
import { ProjectData, ChatMessageData } from './types';
import { projectService } from '../../services/projectService';

interface ProjectHistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onLoadProject: (project: ProjectData, chatHistory?: ChatMessageData[]) => void;
  onNewProject: () => void;
  onPreviewProject: (project: ProjectData) => void;
  onBuildProject: (project: ProjectData) => void;
}

interface SavedProject {
  id: string;
  timestamp: number;
  name: string;
  data: ProjectData;
  chatHistory?: ChatMessageData[];
}

import { safeStorage } from '../../utils/storage';
import { useToast } from '../../context/ToastContext';
import { useConfirm } from '../../context/ConfirmContext';

export default function ProjectHistoryModal({ isOpen, onClose, onLoadProject, onNewProject, onPreviewProject, onBuildProject }: ProjectHistoryModalProps) {
  const { showToast } = useToast();
  const { confirm } = useConfirm();
  const [projects, setProjects] = useState<SavedProject[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [deleteConfirmation, setDeleteConfirmation] = useState<{ isOpen: boolean, projectId: string | null, projectName: string }>({
    isOpen: false,
    projectId: null,
    projectName: ''
  });

  const [isLoading, setIsLoading] = useState(true);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      loadHistory();
    }
  }, [isOpen]);

  const loadHistory = async () => {
    setIsLoading(true);
    try {
      const fetchedProjects = await projectService.getProjects();
      setProjects(fetchedProjects);
    } catch (e) {
      console.error("Failed to load project history from idb", e);
      // Fallback to local storage if idb fails
      try {
        const historyStr = safeStorage.getItem('ham_project_history');
        if (historyStr) {
          setProjects(JSON.parse(historyStr));
        }
      } catch (e: any) {
        console.error("Failed to load project history from local storage", e);
        showToast(`Gagal memuat riwayat proyek: ${e.message}`, 'error');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteClick = (project: SavedProject, e: React.MouseEvent) => {
    e.stopPropagation();
    setDeleteConfirmation({
      isOpen: true,
      projectId: project.id,
      projectName: project.data.name
    });
  };

  const confirmDelete = async () => {
    if (!deleteConfirmation.projectId) return;

    try {
      await projectService.deleteProject(deleteConfirmation.projectId);
      setProjects(prev => prev.filter(p => p.id !== deleteConfirmation.projectId));
      setDeleteConfirmation({ isOpen: false, projectId: null, projectName: '' });
      showToast("Project deleted successfully.", "success");
    } catch (e) {
      console.error("Failed to delete project from idb", e);
      showToast("Failed to delete project. Please try again.", "error");
    }
  };

  const handleClearAll = async () => {
    if (await confirm("Are you sure you want to clear ALL project history?")) {
      try {
        await projectService.clearAllProjects();
        setProjects([]);
        showToast("All project history cleared.", "success");
      } catch (e) {
        console.error("Failed to clear all projects from idb", e);
        showToast("Failed to clear history. Please try again.", "error");
      }
    }
  };

  const handleImportZip = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setIsLoading(true);
      const zip = new JSZip();
      const zipContent = await zip.loadAsync(file);

      const files: { path: string; content: string }[] = [];

      for (const [path, zipEntry] of Object.entries(zipContent.files)) {
        if (!zipEntry.dir) {
          const content = await zipEntry.async("string");
          files.push({ path, content });
        }
      }

      const projectName = file.name.replace('.zip', '');
      const newProjectData: ProjectData = {
        id: `imported-${Date.now()}`,
        name: projectName,
        files: files,
        dependencies: {},
        chatHistory: [{ role: 'ai', content: `Project imported from ${file.name}` }]
      };

      const newRecord = {
        id: newProjectData.id,
        timestamp: Date.now(),
        name: projectName,
        data: newProjectData,
        chatHistory: newProjectData.chatHistory || []
      };

      await projectService.saveProject(newRecord);
      await loadHistory();

      onLoadProject(newProjectData, newProjectData.chatHistory);
      showToast("Project imported successfully.", "success");
      onClose();
    } catch (error) {
      console.error("Failed to import project", error);
      showToast("Failed to import project. Please ensure it is a valid zip file.", "error");
    } finally {
      setIsLoading(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  const filteredProjects = projects.filter(p => 
    p.data.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-[var(--bg-primary)]/80 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
      <div className="bg-[var(--bg-secondary)] rounded-2xl w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[80vh] border border-[var(--border-color)] relative">

        {/* Delete Confirmation Overlay */}
        {deleteConfirmation.isOpen && (
          <div className="absolute inset-0 bg-[var(--bg-primary)]/60 backdrop-blur-sm flex items-center justify-center z-50 p-6">
            <div className="bg-[var(--bg-secondary)] border border-red-500/30 rounded-xl p-6 w-full max-w-sm shadow-2xl transform scale-100 transition-all">
              <div className="flex flex-col items-center text-center gap-4">
                <div className="w-12 h-12 rounded-full bg-red-500/20 flex items-center justify-center">
                  <Trash2 size={24} className="text-red-500" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-[var(--text-primary)] mb-1">Hapus Project?</h3>
                  <p className="text-sm text-[var(--text-secondary)]">
                    Apakah Anda yakin ingin menghapus project <span className="text-[var(--text-primary)] font-semibold">"{deleteConfirmation.projectName}"</span>? 
                    Tindakan ini tidak dapat dibatalkan.
                  </p>
                </div>
                <div className="flex gap-3 w-full mt-2">
                  <button 
                    onClick={() => setDeleteConfirmation({ isOpen: false, projectId: null, projectName: '' })}
                    className="flex-1 py-2 px-4 bg-[var(--bg-tertiary)] hover:bg-[var(--bg-secondary)] text-[var(--text-primary)] text-sm font-medium rounded-lg transition-colors"
                  >
                    Batal
                  </button>
                  <button 
                    onClick={confirmDelete}
                    className="flex-1 py-2 px-4 bg-red-600 hover:bg-red-500 text-white text-sm font-medium rounded-lg transition-colors shadow-lg shadow-red-500/20"
                  >
                    Ya, Hapus
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        <div className="px-3 py-2 border-b border-[var(--border-color)] flex items-center justify-between shrink-0 bg-[var(--bg-tertiary)]">
          <div className="flex items-center gap-2">
            <Clock size={16} className="text-blue-400" />
            <h3 className="font-semibold text-[var(--text-primary)] text-sm">Project History</h3>
          </div>
          <div className="flex items-center gap-2">
            <input 
              type="file" 
              accept=".zip" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleImportZip} 
            />
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-1 px-2 py-1 bg-green-600 hover:bg-green-500 text-white text-[11px] font-medium rounded-md transition-colors shadow-lg shadow-green-500/20"
              title="Import Project from ZIP"
            >
              <Upload size={12} />
              Import
            </button>
            <button 
              onClick={() => {
                onNewProject();
                onClose();
              }}
              className="flex items-center gap-1 px-2 py-1 bg-blue-600 hover:bg-blue-500 text-white text-[11px] font-medium rounded-md transition-colors shadow-lg shadow-blue-500/20"
            >
              <Plus size={12} />
              New Project
            </button>
            <button onClick={onClose} className="p-1 text-[var(--text-secondary)] hover:text-blue-400 rounded-full hover:bg-[var(--bg-secondary)] transition-colors">
              <X size={18} />
            </button>
          </div>
        </div>

        <div className="p-2 border-b border-[var(--border-color)] shrink-0 bg-[var(--bg-tertiary)]">
          <input 
            type="text"
            placeholder="Search projects..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full px-2.5 py-1.5 bg-[var(--bg-primary)] border border-[var(--border-color)] rounded-md text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500 transition-colors"
          />
        </div>

        <div className="p-2 overflow-y-auto flex-1 bg-[var(--bg-primary)]">
          {isLoading ? (
            <div className="space-y-3 p-2">
              {[1, 2, 3].map(i => (
                <div key={i} className="bg-[var(--bg-secondary)] p-3 rounded-lg border border-[var(--border-color)] animate-pulse flex items-center gap-3">
                  <div className="w-8 h-8 bg-[var(--bg-tertiary)] rounded-md"></div>
                  <div className="flex-1 space-y-2">
                    <div className="h-3 bg-[var(--bg-tertiary)] rounded w-3/4"></div>
                    <div className="h-2 bg-[var(--bg-tertiary)] rounded w-1/2"></div>
                  </div>
                </div>
              ))}
            </div>
          ) : filteredProjects.length === 0 ? (
            <div className="text-center text-[var(--text-secondary)] py-12">
              <Folder size={48} className="mx-auto mb-4 opacity-20 text-blue-400" />
              <p>No project history found.</p>
              <p className="text-sm mt-1 opacity-70">Projects you build will appear here.</p>
            </div>
          ) : (
            <div className="space-y-2">
              {filteredProjects.map((project) => (
                <div 
                  key={project.id}
                  onClick={() => {
                    onLoadProject(project.data, project.chatHistory);
                    onClose();
                  }}
                  className="bg-[var(--bg-secondary)] p-2.5 rounded-lg border border-[var(--border-color)] shadow-sm hover:border-blue-500/50 hover:shadow-blue-500/10 transition-all cursor-pointer flex items-center justify-between group"
                >
                  <div className="flex items-center gap-2.5 overflow-hidden">
                    <div className="p-1.5 bg-blue-500/10 text-blue-400 rounded-md shrink-0">
                      <Folder size={16} />
                    </div>
                    <div className="truncate">
                      <h4 className="font-medium text-[var(--text-primary)] truncate text-xs">{project.data.name}</h4>
                      <p className="text-[11px] text-[var(--text-secondary)] mt-0.5">
                        {new Date(project.timestamp).toLocaleString()} • {project.data.files.length} files
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-1">
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        onPreviewProject(project.data);
                      }}
                      className="p-1 text-[var(--text-secondary)] hover:text-blue-400 hover:bg-blue-500/10 rounded-md transition-all shrink-0 flex items-center gap-1"
                      title="Preview Full Project"
                    >
                      <Maximize2 size={12} />
                    </button>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        onBuildProject(project.data);
                        onClose();
                      }}
                      className="p-1 text-[var(--text-secondary)] hover:text-green-400 hover:bg-green-500/10 rounded-md transition-all shrink-0 flex items-center gap-1"
                      title="Build/Run Project"
                    >
                      <Play size={12} />
                    </button>
                    <button 
                      onClick={(e) => handleDeleteClick(project, e)}
                      className="p-1 text-[var(--text-secondary)] hover:text-red-500 hover:bg-red-500/10 rounded-md transition-all shrink-0 flex items-center gap-1"
                      title="Delete Project"
                    >
                      <Trash2 size={12} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {projects.length > 0 && (
          <div className="px-3 py-2 border-t border-[var(--border-color)] bg-[var(--bg-tertiary)] flex justify-end shrink-0">
            <button 
              onClick={handleClearAll}
              className="text-xs font-medium text-red-400 hover:text-red-300 hover:bg-red-500/10 px-2 py-1 rounded-md transition-colors"
            >
              Clear All History
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

