  setIsMoreMenuOpen: (isOpen: boolean) => void;
  setIsSettingsOpen: (isOpen: boolean) => void;
  setIsExportManagerOpen: (isOpen: boolean) => void;
  setIsApkBuilderOpen: (isOpen: boolean) => void;
  setIsHistoryOpen: (isOpen: boolean) => void;
