  isMoreMenuOpen,
  setIsMoreMenuOpen,
  setIsSettingsOpen,
  setIsExportManagerOpen,
  setIsApkBuilderOpen,
  setIsHistoryOpen,
  setShowWelcome
}: StudioOverlayControlsProps) {
  // Close menu when clicking outside
