    }));
  };

  const closeAllModals = () => {
    setModals(prev => {
      const closed = { ...prev };
      (Object.keys(closed) as Array<keyof typeof modals>).forEach(key => {
        closed[key] = false;
      });
      return closed;
    });
  };

  return {
    modals,
    toggleModal,
    closeAllModals
  };
}

