  if (!isOpen) return null;

  const [mood, setMood] = useState<'Chill' | 'Energetic' | 'Focus' | 'Cyberpunk'>('Chill');
  const [isAutoPilot, setIsAutoPilot] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
