          onToggleCommand={() => {
            setIsJokeyOpen(!isJokeyOpen);
            showToast(!isJokeyOpen ? 'AI Auto-Pilot Activated' : 'AI Auto-Pilot Deactivated', !isJokeyOpen ? 'success' : 'info');
