              </div>

              <button 
                onClick={() => {
                  setIncognitoMode(!incognitoMode);
                  setIsMenuOpen(false);
                  showToast(incognitoMode ? 'Incognito Mode Disabled' : 'Incognito Mode Enabled', 'info');
